import { useCallback, useMemo } from 'react';
import { AllPossibleBlockchainSymbol } from 'cb-wallet-data/chains/blockchains';
import { LedgerAddressOption } from 'cb-wallet-data/stores/HardwareWallet/state';
import { getTruncatedAddress } from 'cb-wallet-data/utils/getTruncatedAddress';
import { PaletteForeground } from '@cbhq/cds-common';
import { ListCell } from '@cbhq/cds-web/cells';
import { Checkbox } from '@cbhq/cds-web/controls';
import { Icon } from '@cbhq/cds-web/icons';
import { HStack, Spacer } from '@cbhq/cds-web/layout';
import { PressableOpacity } from '@cbhq/cds-web/system';
import { TextBody } from '@cbhq/cds-web/typography';

type Props = {
  addressOption: LedgerAddressOption;
  onPress: (addressOption: LedgerAddressOption) => void;
  isSelected: boolean;
  blockchainSymbol: AllPossibleBlockchainSymbol;
  disabled?: boolean;
  hasAddressBeenOnboarded?: boolean;
  onDisabledCheckboxPress?: () => void;
};

export function AddressCell({
  addressOption,
  isSelected,
  onPress,
  blockchainSymbol,
  disabled,
  hasAddressBeenOnboarded,
  onDisabledCheckboxPress,
}: Props) {
  const handlePress = useCallback(() => {
    onPress(addressOption);
  }, [onPress, addressOption]);

  const leftSideTextColor = useMemo((): PaletteForeground => {
    if (hasAddressBeenOnboarded || isSelected) return 'foreground';

    if (disabled) return 'foregroundMuted';

    return 'foreground';
  }, [disabled, hasAddressBeenOnboarded, isSelected]);

  const formattedTitle = useMemo(
    () => (
      <HStack spacing={0}>
        <TextBody color={leftSideTextColor} spacing={0} spacingEnd={1} as="p">
          {`${addressOption.index + 1}.`}
        </TextBody>
        <TextBody color={leftSideTextColor} as="span">
          {getTruncatedAddress(addressOption.address)}
        </TextBody>
      </HStack>
    ),
    [addressOption.address, addressOption.index, leftSideTextColor],
  );

  const balanceAndBlockchainTextColor = useMemo((): PaletteForeground => {
    if (disabled && !isSelected) return 'foregroundMuted';

    return 'foreground';
  }, [disabled, isSelected]);

  const checkboxComponent = useMemo(() => {
    if (hasAddressBeenOnboarded)
      return (
        <Icon
          testID={`${addressOption.address}-checkmark-icon`}
          color="foregroundMuted"
          size="s"
          name="checkmark"
        />
      );

    if (disabled) {
      return (
        <PressableOpacity onPress={!isSelected ? onDisabledCheckboxPress : undefined}>
          <Checkbox
            disabled={!isSelected && disabled}
            testID={`${addressOption.address}-checkbox`}
            checked={isSelected}
            onChange={handlePress}
          />
        </PressableOpacity>
      );
    }

    return (
      <Checkbox
        testID={`${addressOption.address}-checkbox`}
        checked={isSelected}
        onChange={handlePress}
      />
    );
  }, [
    addressOption.address,
    disabled,
    handlePress,
    hasAddressBeenOnboarded,
    isSelected,
    onDisabledCheckboxPress,
  ]);

  const actionComponents = useMemo(() => {
    return (
      <HStack alignItems="center">
        <TextBody
          color={balanceAndBlockchainTextColor}
          as="span"
        >{`${addressOption.balance} ${blockchainSymbol}`}</TextBody>
        <Spacer horizontal={2} />
        {checkboxComponent}
      </HStack>
    );
  }, [addressOption.balance, balanceAndBlockchainTextColor, blockchainSymbol, checkboxComponent]);

  const action = useMemo(() => {
    if (disabled) {
      return actionComponents;
    }
    return actionComponents;
  }, [actionComponents, disabled]);

  return (
    <ListCell
      testID={addressOption.address}
      key={addressOption.address}
      title={formattedTitle}
      variant="positive"
      action={action}
      compact
    />
  );
}

import { screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { logLedgerMaxAddressReached } from 'cb-wallet-analytics/ledger';
import { mockUseIsFeatureEnabled } from 'cb-wallet-data/FeatureManager/utils/mockUseIsFeatureEnabled';
import { useNumberOfSelectedAddresses } from 'cb-wallet-data/stores/HardwareWallet/hooks/useNumberOfSelectedAddresses';
import { WALLET_GROUP_LIMIT } from 'cb-wallet-data/test/fixtures/WalletGroup';
import { useToast } from 'wallet-cds-extension/overrides/@cbhq/cds-web/overlays/useToast';
import { useStepper } from 'wallet-cds-web/external-libs/stepper';
import { renderWithAllProviders } from 'wallet-cds-web/test/testUtils';

import { AddressTable } from '../AddressTable/AddressTable';

import { SelectAddresses } from './SelectAddresses';

mockUseIsFeatureEnabled({
  wallet_group_limit_increase: true,
  wallet_redesign_miami_vice: false,
  wallet_app_architecture: false,
});

jest.mock('cb-wallet-analytics/ledger');
jest.mock('wallet-cds-web/external-libs/stepper');
jest.mock('cb-wallet-data/stores/HardwareWallet/hooks/useNumberOfSelectedAddresses');
jest.mock('cb-wallet-data/hooks/useMiamiIllustrationsEnabled/useMiamiIllustrationsEnabled');
jest.mock('wallet-cds-extension/overrides/@cbhq/cds-web/overlays/useToast');

jest.mock('async-mutex', () => ({
  Mutex: class MockMutex {
    async waitForUnlock() {
      return Promise.resolve();
    }

    acquire() {}
  },
}));

const mockAccounts = [
  {
    index: 0,
    address: '<Test-address-1>',
    balance: 0,
    derivationPath: `m/44'/60'/0'/0`,
  },
  {
    index: 0,
    address: '<Test-address-2>',
    balance: 0,
    derivationPath: `m/44'/60'/0'/0`,
  },
];
const mockTriggerDisableCheckboxClick = jest.fn();
jest.mock(':extension/components/HardwareWallet/AddressTable/AddressTable', () => ({
  AddressTable: (props: React.ComponentProps<typeof AddressTable>) => {
    mockTriggerDisableCheckboxClick.mockImplementation(() => {
      props.onDisabledCheckboxPress?.();
    });

    return (
      <>
        {mockAccounts.map((a, i) => (
          <button
            // eslint-disable-next-line react/no-array-index-key
            key={i}
            onClick={() => props.onSelected?.(a)}
            data-testid={`mock-address-row-${i}`}
          />
        ))}
      </>
    );
  },
}));

describe('<SelectAddresses />', () => {
  const mockShowToast = jest.fn();
  const mockClearToastQueue = jest.fn();
  const mockHideToast = jest.fn();

  beforeEach(() => {
    (useNumberOfSelectedAddresses as jest.Mock).mockReturnValue(0);
    (useToast as jest.Mock).mockReturnValue({
      show: mockShowToast,
      clearQueue: mockClearToastQueue,
      hide: mockHideToast,
    });
    const mockGoToStep = jest.fn();
    (useStepper as jest.Mock).mockImplementation(() => ({
      goToStep: mockGoToStep,
    }));
  });

  it('should update the selected HD path option when an HD path is selected', async () => {
    renderWithAllProviders(
      <SelectAddresses
        context="ledger-onboarding"
        onContinue={jest.fn()}
        onGetAddressError={jest.fn()}
      />,
    );

    expect(screen.getByTestId('Ledger Live (ETH)-hd-path-dropdown')).toBeInTheDocument();
    await userEvent.click(screen.getByTestId('Ledger Live (ETH)-hd-path-dropdown'));
    await userEvent.click(screen.getByTestId('Default (ETH)-hd-path-select-option'));
    expect(await screen.findByTestId('Default (ETH)-hd-path-dropdown')).toBeTruthy();
  });

  it('should display the correct copy when multiple addresses are selected', async () => {
    (useNumberOfSelectedAddresses as jest.Mock).mockReturnValue(2);
    renderWithAllProviders(
      <SelectAddresses
        context="ledger-onboarding"
        onContinue={jest.fn()}
        onGetAddressError={jest.fn()}
      />,
    );

    await userEvent.click(screen.getByTestId('mock-address-row-0'));
    await userEvent.click(screen.getByTestId('mock-address-row-1'));
    expect(screen.getByTestId('ledger-hw-select-addresses-continue')).toBeEnabled();
    expect(screen.getByTestId('ledger-hw-select-addresses-continue')).toHaveTextContent(
      'Add 2 addresses',
    );
  });

  it('should display the correct copy when one address is selected', async () => {
    (useNumberOfSelectedAddresses as jest.Mock).mockReturnValue(1);
    renderWithAllProviders(
      <SelectAddresses
        context="ledger-onboarding"
        onContinue={jest.fn()}
        onGetAddressError={jest.fn()}
      />,
    );

    await userEvent.click(screen.getByTestId('mock-address-row-0'));
    expect(screen.getByTestId('ledger-hw-select-addresses-continue')).toBeEnabled();
    expect(screen.getByTestId('ledger-hw-select-addresses-continue')).toHaveTextContent(
      'Add 1 address',
    );
  });

  it('should display the correct copy and disable the button when no addresses are selected', () => {
    renderWithAllProviders(
      <SelectAddresses
        context="ledger-onboarding"
        onContinue={jest.fn()}
        onGetAddressError={jest.fn()}
      />,
    );
    expect(screen.getByTestId('ledger-hw-select-addresses-continue')).toBeDisabled();
    expect(screen.getByTestId('ledger-hw-select-addresses-continue')).toHaveTextContent(
      'Select address',
    );
  });

  it('should call onContinue when the continue CTA is clicked', async () => {
    const mockOnContinue = jest.fn();
    (useNumberOfSelectedAddresses as jest.Mock).mockReturnValue(1);
    renderWithAllProviders(
      <SelectAddresses
        context="ledger-onboarding"
        onContinue={mockOnContinue}
        onGetAddressError={jest.fn()}
      />,
    );

    await waitFor(() => {
      expect(mockOnContinue).not.toHaveBeenCalled();
    });
    expect(mockHideToast).not.toHaveBeenCalled();

    await userEvent.click(screen.getByTestId('mock-address-row-0'));
    await userEvent.click(screen.getByTestId('ledger-hw-select-addresses-continue'));

    await waitFor(() => {
      expect(mockOnContinue).toHaveBeenCalledTimes(1);
    });
    expect(mockHideToast).toHaveBeenCalledTimes(1);
  });

  it('should not show a toast if there are 100 selected addresses', async () => {
    (useNumberOfSelectedAddresses as jest.Mock).mockReturnValue(WALLET_GROUP_LIMIT);
    const mockOnContinue = jest.fn();
    renderWithAllProviders(
      <SelectAddresses
        context="ledger-onboarding"
        onContinue={mockOnContinue}
        onGetAddressError={jest.fn()}
      />,
    );
    await waitFor(() => {
      expect(mockShowToast).not.toHaveBeenCalled();
    });
  });

  it('should show a toast when the user clicks on a disabled checkbox once 100 addresses have been selected', async () => {
    (useNumberOfSelectedAddresses as jest.Mock).mockReturnValue(WALLET_GROUP_LIMIT);
    renderWithAllProviders(
      <SelectAddresses
        context="ledger-onboarding"
        onContinue={jest.fn()}
        onGetAddressError={jest.fn()}
      />,
    );

    await waitFor(() => {
      expect(mockShowToast).not.toHaveBeenCalled();
    });

    mockTriggerDisableCheckboxClick();

    await waitFor(() => {
      expect(mockShowToast).toHaveBeenCalledTimes(1);
    });
    expect(mockShowToast).toHaveBeenCalledWith('The current limit is 100 addresses', {
      bottomOffset: 0,
      hideCloseButton: true,
    });

    expect(logLedgerMaxAddressReached).toHaveBeenCalledWith({ context: 'ledger-onboarding' });
  });
});

