import { useCallback, useMemo, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import {
  ethereumAddressDerivationPath,
  EthereumBlockchain,
  TxMetadataKey_txSource,
} from 'cb-wallet-data/chains/AccountBased/Ethereum/config';
import { ETHEREUM_SYMBOL } from 'cb-wallet-data/chains/AccountBased/Ethereum/constants';
import { isValidAddress } from 'cb-wallet-data/chains/AccountBased/Ethereum/utils/isValidAddress';
import { importAddress } from 'cb-wallet-data/chains/AccountBased/operations/importAddress';
import { useActiveAccountIdForEscapeHatch } from 'cb-wallet-data/stores/Accounts/hooks/useActiveAccountId';
import { Account } from 'cb-wallet-data/stores/Accounts/models/Account';
import { AccountType } from 'cb-wallet-data/stores/Accounts/models/AccountTypes';
import { useSignInWithMnemonic } from 'cb-wallet-data/stores/Authentication/signIn/useSignInWithMnemonic';
import { useSignInWithWalletLink } from 'cb-wallet-data/stores/Authentication/signIn/useSignInWithWalletLink';
import { useClearAuthTokens } from 'cb-wallet-data/stores/Authentication/tokens/useClearAuthTokens';
import { useClearWalletLinkAuthStatus } from 'cb-wallet-data/stores/Authentication/walletLink/useClearWalletLinkAuthStatus';
import { useSignAndSubmitTransactionViaWalletLink } from 'cb-wallet-data/stores/Transactions/hooks/useSignAndSubmitTransactionViaWalletLink';
import { generateUnsignedTransaction } from 'cb-wallet-data/stores/Transactions/methods/generateUnsignedTransaction';
import {
  TxMetadataKey,
  TxMetadataValue,
} from 'cb-wallet-data/stores/Transactions/models/TxMetadataKey';
import { Success } from 'cb-wallet-data/stores/Transactions/models/UnsignedTxResult';
import { useCreateUserWithMnemonic } from 'cb-wallet-data/stores/User/hooks/useCreateUserWithMnemonic';
import { useValidateUsername } from 'cb-wallet-data/stores/User/hooks/useValidateUsername';
import { viewedTOSUpdateAtom } from 'cb-wallet-data/stores/User/state';
import { useCreateWalletGroups } from 'cb-wallet-data/stores/WalletGroups/hooks/useCreateWalletGroups';
import { useSetActiveWalletGroupId } from 'cb-wallet-data/stores/WalletGroups/hooks/useSetActiveWalletGroupId';
import { walletsArraySelector } from 'cb-wallet-data/stores/Wallets/state';
import {
  ImportableAddressesByBlockchain,
  importAddressesByBlockchain,
} from 'cb-wallet-data/stores/Wallets/utils/importAddressesByBlockchain';
import { useRecoilValue, useSetRecoilState } from 'recoil';
import { Button } from '@cbhq/cds-web/buttons';
import { TextInput } from '@cbhq/cds-web/controls/TextInput';
import { VStack } from '@cbhq/cds-web/layout';

import { AppLockRepository } from ':extension/datalayer/application/repositories/AppLockRepository';
import { walletLinkRelay } from ':extension/datalayer/WalletLink/walletLinkRelay';

const DEBUG_FAUX_WALLET_INDEX = 9999;

function setForceUpdateTemplate() {
  chrome.action.setPopup({ popup: 'forceUpdateTemplate.html' });
}

function setForceUpdateFinal() {
  chrome.action.setPopup({ popup: 'forceUpdate.html' });
}

function clearForceUpdate() {
  chrome.action.setPopup({ popup: 'index.html?inPageRequest=false' });
}

const messages = defineMessages({
  overrideWalletGroupNickname: {
    defaultMessage: 'Debug: ETH Override',
    description: 'Default nickname given to debug wallet group',
  },
});

export function DebugButtons() {
  const wallets = useRecoilValue(walletsArraySelector);
  const signInWithWalletLink = useSignInWithWalletLink();
  const [overrideWalletAddress, setOverrideWalletAddress] = useState<string>();
  const { formatMessage } = useIntl();
  const createWalletGroups = useCreateWalletGroups();
  const setActiveWalletGroupId = useSetActiveWalletGroupId();
  const activeAccountId = useActiveAccountIdForEscapeHatch();
  const appLockRepository = useMemo(() => {
    return new AppLockRepository();
  }, []);

  const signInViaWalletlink = async () => signInWithWalletLink(walletLinkRelay.selectedAddress!);

  const importWalletsWithAddress = useCallback(async () => {
    if (!walletLinkRelay.selectedAddress) {
      alert('Please connect wallet before importing wallet addresses');
      return;
    }
    const accountId = Account.generateID(
      AccountType.WALLET_LINK,
      ETHEREUM_SYMBOL,
      walletLinkRelay.selectedAddress,
    );
    const importableAddressesByBlockchain: ImportableAddressesByBlockchain = {
      [ETHEREUM_SYMBOL]: [
        {
          index: 0n,
          address: walletLinkRelay.selectedAddress,
          accountId,
        },
      ],
    };

    await importAddressesByBlockchain(importableAddressesByBlockchain);
    appLockRepository.isAppUnlocked = true;
  }, [appLockRepository]);

  const overrideWalletsWithAddress = useCallback(async () => {
    try {
      if (!overrideWalletAddress) {
        return;
      }

      const walletIndex = BigInt(DEBUG_FAUX_WALLET_INDEX);

      const walletGroupToCreateOptions = {
        accountId: activeAccountId,
        walletIndex,
        nickname: formatMessage(messages.overrideWalletGroupNickname),
      };

      const importableAddress = {
        index: walletIndex,
        address: overrideWalletAddress,
        accountId: activeAccountId,
        derivationPath: ethereumAddressDerivationPath(walletIndex),
      };

      const [[createdWalletGroup]] = await Promise.all([
        createWalletGroups([walletGroupToCreateOptions]),
        importAddress(ETHEREUM_SYMBOL, importableAddress),
      ]);

      setActiveWalletGroupId(createdWalletGroup.id);
    } catch (error) {
      alert(`Couldn't override wallet address ${error}`);
    }
    appLockRepository.isAppUnlocked = true;
  }, [
    activeAccountId,
    createWalletGroups,
    setActiveWalletGroupId,
    formatMessage,
    overrideWalletAddress,
    appLockRepository,
  ]);

  const { signInWithMnemonic } = useSignInWithMnemonic();
  const signInViaMnemonic = () => {
    signInWithMnemonic({
      mnemonic: 'mansion turn clock casual share weird thought only parent equip abuse track',
    });
  };

  const createUserWithMnemonic = useCreateUserWithMnemonic();
  const createUser = () => {
    createUserWithMnemonic({
      username: 'fakeUsername',
      isPublic: true,
      mnemonic:
        'practice rocket across above series peace private trade street skirt aware squeeze',
    });
  };

  const validateUsername = useValidateUsername();
  const validateName = () => {
    validateUsername('fakeUsername');
  };

  const clearAuthTokens = useClearAuthTokens();
  const clearWalletLinkAuthStatus = useClearWalletLinkAuthStatus();
  const resetAuthentication = () => {
    clearAuthTokens();
    clearWalletLinkAuthStatus();
  };

  const signAndSubmitViaWalletLink = useSignAndSubmitTransactionViaWalletLink();

  const sendEthTransaction = async () => {
    // Only works if you have eth in your wallet
    const ethWallet = wallets.find(
      (wallet) => wallet.blockchain.rawValue === EthereumBlockchain.rawValue,
    );
    if (!ethWallet) return;

    const metadata = new Map<TxMetadataKey, TxMetadataValue>([[TxMetadataKey_txSource, 'send']]);

    const unsignedTxResult = await generateUnsignedTransaction({
      wallet: ethWallet,
      transactionAmount: { kind: 'Amount', value: 1n },
      recipientAddress: ethWallet.primaryAddress,
      metadata,
      txConfiguration: {
        txType: 'Legacy',
        nonce: 0n,
      },
    });

    await signAndSubmitViaWalletLink({
      unsignedTx: unsignedTxResult.transaction!,
      wallet: (unsignedTxResult as Success).wallet,
    });
  };

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleAddress = useCallback((event: any) => {
    const walletAddress = event.target.value;
    if (isValidAddress(walletAddress)) {
      setOverrideWalletAddress(walletAddress);
    } else {
      alert('Enter a valid ETH address');
    }
  }, []);

  const setViewedTOSUpdate = useSetRecoilState(viewedTOSUpdateAtom);

  const resetTOSUpdate = useCallback(() => {
    setViewedTOSUpdate(false);
  }, [setViewedTOSUpdate]);

  return (
    <VStack>
      <Button block onPress={signInViaWalletlink}>
        Sign in With Walletlink
      </Button>
      <p />
      <Button block onPress={signInViaMnemonic}>
        Sign in With Mnemonic
      </Button>
      <p />
      <Button block onPress={importWalletsWithAddress}>
        Import Wallets With Address
      </Button>
      <p />
      <TextInput
        label="Override Wallet Address"
        placeholder="Enter ETH wallet address"
        onChange={handleAddress}
      />
      <p />
      <Button block onPress={overrideWalletsWithAddress}>
        Override Wallets With Address
      </Button>
      <p />
      <Button block onPress={createUser}>
        Create User
      </Button>
      <p />
      <Button block onPress={validateName}>
        Validate username
      </Button>
      <p />
      <Button block onPress={sendEthTransaction}>
        Send ETH transaction (requires ETH)
      </Button>
      <p />
      <Button block onPress={setForceUpdateTemplate}>
        Set force update view template
      </Button>
      <p />
      <Button block onPress={setForceUpdateFinal}>
        Set force update view final page
      </Button>
      <p />
      <Button block onPress={clearForceUpdate}>
        Clear force update
      </Button>
      <p />
      <Button block onPress={resetAuthentication}>
        Reset authentication
      </Button>
      <p />
      <Button block onPress={resetTOSUpdate}>
        Reset TOS update flag
      </Button>
    </VStack>
  );
}

