export function DebugEthTx() {
  const [weiAmount, setWeiAmount] = useState<number>();
  const [gasLimit, setGasLimit] = useState<number | undefined>();
  const [recipientAddr, setRecipientAddr] = useState<string>();
  const [unsignedTx, setUnsignedTx] = useState<UnsignedTxResult>();
  const [unsignedTxString, setUnsignedTxString] = useState<string | undefined>();
  const [enableSignAndSubmit, setEnableSignAndSubmit] = useState<boolean>(false);
  const [signedSubmittedTx, setSignedSubmittedTx] = useState<SignedTx | undefined>();
  const [createTxError, setCreateTxError] = useState<string | undefined>();
  const [submitTxError, setSubmitTxError] = useState<string | undefined>();
  const [selectedWalletId, setSelectedWalletId] = useState<string>();
  const [selectedWallet, setSelectedWallet] = useState<Wallet>();
  const activeAccountId = useActiveAccountId();

  useSetWallets();
  const wallets = useRecoilValue(walletsArraySelector);

  useEffect(() => {
    setUnsignedTxString(
      unsignedTx
        ? JSON.stringify(
            unsignedTx,
            (_key, value) => (typeof value === 'bigint' ? `${value.toString()}n` : value),
            2,
          )
        : unsignedTx,
    );
    setEnableSignAndSubmit(unsignedTx?.kind === 'Success');
  }, [unsignedTx]);

  useEffect(() => {
    const wallet = wallets.find((w) => w.id === selectedWalletId);
    setSelectedWallet(wallet);
  }, [selectedWalletId, wallets]);

  const handleReset = useCallback(() => {
    setUnsignedTx(undefined);
    setSignedSubmittedTx(undefined);
    setSubmitTxError(undefined);
    setCreateTxError(undefined);
    setWeiAmount(undefined);
    setGasLimit(undefined);
    setRecipientAddr(undefined);
  }, []);

  const handleCreateTransaction = useCallback(async () => {
    handleReset();

    if (weiAmount === undefined) {
      setCreateTxError('You must set an Eth Amount >= 0');
      return null;
    }
    if (!selectedWallet) {
      setCreateTxError(
        'No wallet found, please onboard through the extension to activate a wallet',
      );
      return null;
    }
    if (!recipientAddr) {
      setCreateTxError('You must provide a recipient address');
      return null;
    }
    setCreateTxError(undefined);
    const metadata = new Map<TxMetadataKey, TxMetadataValue>([[TxMetadataKey_txSource, 'send']]);
    const txAmount: TransferValue = {
      kind: 'Amount',
      value: BigInt(weiAmount),
    };
    const txGasLimit = gasLimit !== undefined ? BigInt(gasLimit) : undefined;
    const unsignedTxResult = await generateUnsignedTransaction({
      wallet: selectedWallet,
      transactionAmount: txAmount,
      recipientAddress: recipientAddr,
      metadata,
      txConfiguration: {
        selectedGasPrice: undefined,
        selectedGasLimit: txGasLimit,
        txType: 'Legacy',
      },
    });
    setUnsignedTx(unsignedTxResult);
  }, [gasLimit, handleReset, recipientAddr, selectedWallet, weiAmount]);

  const handleSubmitSignAndSubmitTransaction = useCallback(async () => {
    setSubmitTxError(undefined);
    if (!unsignedTx?.transaction || unsignedTx.kind === 'Failure') {
      setSubmitTxError(
        'You need a successful unsigned transaction before you can sign and submit it.',
      );
      return;
    }
    if (!selectedWallet) {
      setSubmitTxError(
        'No wallet found, please onboard through the extension to activate a wallet',
      );
      return;
    }

    try {
      await appLockRepository.submitPassword(
        'password123',
        activeAccountId,
        SecretAccessContext.DebugMenu,
        false,
      );
      try {
        const txSubmissionType = 'original';

        const tx = await signAndSubmitTransaction({
          unsignedTx: unsignedTx.transaction,
          wallet: selectedWallet,
          txSubmissionType,
          onSubmit: () => {},
        });
        setSubmitTxError(undefined);
        setSignedSubmittedTx(tx);
      } catch (error) {
        setSubmitTxError(`SUBMISSION ERROR: ${error}`);
        return;
      }
    } catch (error) {
      setSubmitTxError(`MNEMONIC ERROR: ${error}`);
    }
  }, [activeAccountId, selectedWallet, unsignedTx]);

  const handleWeiAmountChange = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ({ target }: any) => setWeiAmount(Number(target.value) >= 0 ? Number(target.value) : undefined),
    [],
  );

  const handleGasLimitChange = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ({ target }: any) => setGasLimit(Number(target.value) >= 1 ? Number(target.value) : undefined),
    [],
  );

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleAddressChange = useCallback(({ target }: any) => setRecipientAddr(target.value), []);
  const handleWalletChange = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ({ target }: any) => setSelectedWalletId(target.value),
    [],
  );

  return (
    <>
      <h1>{strings.pageTitle}</h1>
      <hr />
      <Button type="button" onPress={handleReset}>
        {strings.reset}
      </Button>
      <h3 style={{ background: '#ff4242', color: 'white' }}>{createTxError}</h3>
      <h3>{strings.createSectionTitle}</h3>
      <form>
        <div>
          {!!wallets && (
            <select onChange={handleWalletChange} defaultValue={selectedWalletId}>
              <option value={undefined}>{strings.selectWallet}</option>
              {wallets.map((wallet) => (
                <option value={wallet.id}>
                  {wallet.currencyCode.code} | {wallet.displayName}
                </option>
              ))}
            </select>
          )}
        </div>
        <div>
          <Label htmlFor="weiAmount">{strings.weiAmount}</Label>
          <Input
            type="number"
            id="weiAmount"
            name="weiAmount"
            placeholder="n/a"
            min="0"
            onChange={handleWeiAmountChange}
            defaultValue={weiAmount}
          />
        </div>
        <div>
          <Label htmlFor="gasLimit">{strings.gasLimit}</Label>{' '}
          <Input
            type="number"
            id="gasLimit"
            name="gasLimit"
            placeholder="n/a"
            min="1"
            onChange={handleGasLimitChange}
            defaultValue={gasLimit}
          />
          <small>{strings.gasLimitWarning}</small>
        </div>
        <div>
          <Label htmlFor="toAddress">{strings.recipientAddress}</Label>
          <Input
            type="text"
            id="toAddress"
            name="toAddress"
            placeholder="0xabcdef"
            onChange={handleAddressChange}
            defaultValue={recipientAddr}
          />
        </div>
        <Button type="button" onPress={handleCreateTransaction}>
          {strings.createTx}
        </Button>
      </form>
      <div>
        <h3>{strings.planUnsignedTx}</h3>
        <ul>
          <li>
            {strings.weiAmount}: {weiAmount}
          </li>
          <li>
            {strings.gasLimit}: {gasLimit}
          </li>
          <li>
            {strings.recipientAddress}: {recipientAddr}
          </li>
          <li>
            {strings.wallet}: {selectedWallet?.displayName}
            <br />
            {selectedWallet?.currencyCode.code}
            <br />
            {selectedWallet?.primaryAddress}
          </li>
        </ul>
      </div>
      {unsignedTxString && (
        <div>
          <h3>{strings.unsignedTxResult}</h3>
          <code>{unsignedTxString}</code>
        </div>
      )}
      {enableSignAndSubmit && (
        <>
          <h1>{strings.signAndSubmitSectionTitle}</h1>
          <h3 style={{ background: '#ff4242', color: 'white' }}>{submitTxError}</h3>
          {signedSubmittedTx ? (
            <h3 style={{ background: '#2e8b57', color: 'white' }}>{strings.successfulTx}</h3>
          ) : null}
          <Button type="button" onPress={handleSubmitSignAndSubmitTransaction}>
            {strings.signAndSubmitTx}
          </Button>
        </>
      )}
    </>
  );
}

