export const UnlockScreen = memo(
  ({
    onPressForgotPassword,
    isRequestingAllSecrets,
    accountId: requestedAccountId,
  }: UnlockScreenProps) => {
    const { formatMessage } = useIntl();
    const [hasErrors, setHasErrors] = useState<boolean>(false);
    const [password, setPassword] = useState<string>('');
    const [passwordAttempts, setPasswordAttempts] = useState<number>(
      appLockRepository.passwordAttempts,
    );
    const [passwordError, setPasswordError] = useState<boolean>(false);
    const updateAuthTokens = useUpdateAuthTokens();
    const activeAccountId = useActiveAccountIdForEscapeHatch();
    const mnemonicAccounts = useAccountsByAccountType(AccountType.MNEMONIC);
    const privateKeyAccounts = useAccountsByAccountType(AccountType.PRIVATE_KEY);
    const getAccountById = useGetAccountById();
    const accountId = useMemo(() => {
      const activeAccount = getAccountById(activeAccountId);
      if (activeAccount?.isHardwareAccount) {
        return mnemonicAccounts[0]?.id ?? privateKeyAccounts[0]?.id;
      }
      return requestedAccountId ?? activeAccountId;
    }, [activeAccountId, getAccountById, mnemonicAccounts, privateKeyAccounts, requestedAccountId]);

    const isTimedPasswordLockout = passwordAttempts >= MAX_PASSWORD_ATTEMPTS;

    const error = useMemo(() => {
      if (isTimedPasswordLockout) {
        return formatMessage(messages.timedLockOut);
      }
      if (passwordAttempts >= 2) {
        return formatMessage(messages.triesRemaining, {
          numTries: MAX_PASSWORD_ATTEMPTS - passwordAttempts,
        });
      }
      if (passwordError) {
        return formatMessage(messages.wrongPassword);
      }

      return '';
    }, [formatMessage, isTimedPasswordLockout, passwordAttempts, passwordError]);

    const handlePasswordChange = useCallback(
      (value: string): void => {
        // clears the previous givenError state from password validation
        setPasswordError(false);
        setPassword(value);
      },
      [setPassword, setPasswordError],
    );

    const handleSubmit = useCallback(async () => {
      logExtensionUnlockButtonPressed();

      try {
        if (isTimedPasswordLockout) {
          throw new Error(messages.timedLockOut.defaultMessage);
        }
        const unlockResult = await appLockRepository.submitPassword(
          password,
          accountId,
          SecretAccessContext.Unlock,
          isRequestingAllSecrets,
        );

        const numAttempts = unlockResult.numAttempts ?? 0;

        if (numAttempts >= MAX_PASSWORD_ATTEMPTS) {
          logUserPasswordLockOut(numAttempts);
        }

        if (numAttempts > 1 && numAttempts < MAX_PASSWORD_ATTEMPTS) {
          logUserHasLimitedAttemptsRemaining(numAttempts);
        }

        if (unlockResult.status === UNLOCK_STATUSES.SUCCESS && unlockResult.secrets) {
          // re-signing standalone users with mnemonic upon unlock
          updateAuthTokens({
            accountId:
              accountId === NEVER_ACCOUNT_ID ? Object.keys(unlockResult.secrets)[0] : accountId,
          });
        }

        if (unlockResult.status !== UNLOCK_STATUSES.SUCCESS) {
          setPasswordError(true);
          setPasswordAttempts(unlockResult.numAttempts ?? 0);
          newTimer('balance.AppStart'); // Start timer on successful password auth
        }
      } catch (e) {
        setPasswordError(true);
      }
    }, [accountId, isRequestingAllSecrets, isTimedPasswordLockout, password, updateAuthTokens]);

    /**
     * This is used to reauthenticate the extension in case the refresh token expires
     * https://github.cbhq.net/wallet/wallet-mobile/pull/3222
     * https://jira.coinbase-corp.com/browse/WALL-4032
     */
    const listenForUnlock = useObservableCallback((subscription) => {
      if (subscription) subscription.unsubscribe();

      const newSubscription =
        // AppUnlock - just means related to app access as opposed to transaction etc.
        appLockRepository
          .unlock({ ...AppLockTypes.AppAccess })
          .subscribe(async (result: UnlockResult) => {
            if (result.status === UNLOCK_STATUSES.SUCCESS) {
              setPasswordAttempts(0);
            } else {
              setPasswordAttempts(result.numAttempts ?? 0);
              setPasswordError(true);
            }
          });

      return newSubscription;
    }, []);

    useEffect(
      function requestPassword() {
        if (getHasStoredSecrets()) {
          listenForUnlock();
        }
      },
      [listenForUnlock],
    );

    useEffect(function resetPasswordAttemptsToZero() {
      const subscription = appLockRepository.passwordLockOutTimerCleared.subscribe(() => {
        setPasswordAttempts(0);
      });

      return () => subscription?.unsubscribe();
    }, []);

    return (
      <PopupAwareVStack elevation={1} {...styles} spacingHorizontal={2}>
        <LogoHeader />
        <VStack height="100%" />
        <VStack gap={2} justifyContent="flex-end">
          <ValidatedTextInput
            testID="unlock-with-password"
            type="password"
            name="password"
            disabled={isTimedPasswordLockout}
            // ensure the reason for lock-out displays even on app close -> restart
            defaultSubscript={
              isTimedPasswordLockout ? formatMessage(messages.timedLockOut) : undefined
            }
            label={formatMessage(messages.unlockLabel)}
            value={password}
            givenError={error}
            onError={setHasErrors}
            autoFocus
            onChange={handlePasswordChange}
            // don't display any error msg but enforce non-empty
            validators={validators}
            onEnter={handleSubmit}
          />
          <Box>
            <Button
              block
              disabled={
                hasErrors || passwordError || password.length === 0 || isTimedPasswordLockout
              }
              onPress={handleSubmit}
              testID="unlock-wallet-button"
            >
              {formatMessage(messages.unlock)}
            </Button>
          </Box>
          <Button testID="forgot-password-btn" onPress={onPressForgotPassword} transparent>
            <TextHeadline as="span">{formatMessage(messages.forgotPassword)}</TextHeadline>
          </Button>
        </VStack>
      </PopupAwareVStack>
    );
  },
);

