const DISALLOW_ANONYMOUS = false;
const IS_SUBDOMAIN = true;

export const ChangeStep = memo(function ChangeStep() {
  const activeWalletGroupId = useActiveWalletGroupId();
  const { isLoading, username, subdomainSuffix, claim } =
    useSubdomainReservation(activeWalletGroupId);
  const validateUsername = useValidateUsername();
  const validators = useUsernameValidators(DISALLOW_ANONYMOUS, IS_SUBDOMAIN);
  const { goToStep } = useStepper(stepper);
  const [isTermsChecked, { toggle: handleTermsChange }] = useToggler();
  const [isUsernameAvailable, setIsUsernameAvailable] = useState(false);
  const [newUsername, setNewUsername] = useState('');
  const [isValidating, setIsValidating] = useState(false);
  const [isClaiming, setIsClaiming] = useState(false);
  const [hasErrors, setHasErrors] = useState(false);
  const { push } = useHistory();
  const { formatMessage } = useIntl();
  const toast = useToast();

  const { start: markStartClaimStepPerf } = useExtensionPerfMark(
    PERF_MARKS.bridge,
    SUBDOMAIN_MARKS.load_subdomain_claim,
    {
      logMetric: true,
    },
  );

  const givenError = useMemo(() => {
    // only default to "Not Available" if all validators come back clean
    if (!hasErrors && !isUsernameAvailable) {
      return formatMessage(validationMessages.validationNotAvailable);
    }
  }, [formatMessage, hasErrors, isUsernameAvailable]);

  const isDisabled = useMemo(
    () => !isTermsChecked || hasErrors || !newUsername || isValidating || !isUsernameAvailable,
    [hasErrors, isValidating, isTermsChecked, newUsername, isUsernameAvailable],
  );

  const handleBackPress = useCallback(() => {
    markStartClaimStepPerf();
    goToStep('claim');
  }, [goToStep, markStartClaimStepPerf]);

  const handleClaim = useCallback(async () => {
    if (isDisabled) {
      return;
    }

    logSubdomainClaim();
    setIsClaiming(true);

    try {
      await claim(newUsername);
      setIsClaiming(false);
      logSubdomainClaimSuccess();
      push(RoutesEnum.DEFAULT);
    } catch (error) {
      const err = coerceError(error, 'change step');
      logSubdomainClaimError();
      cbReportError({
        error: err,
        context: 'did_error',
        metadata: {
          screen: 'ChangeStep',
          method: 'ChangeStep.handleClaim',
        },
        severity: 'error',
        isHandled: false,
      });
      setIsClaiming(false);
      toast.show(formatMessage(messages.error));
    }
  }, [push, toast, formatMessage, isDisabled, claim, newUsername]);

  const validateName = useCallback(
    async (name: string) => {
      try {
        // If the user enters their current username, skip checking if the username is available
        // since they already exist and would fail the check.
        const isClaimingSameName = name.toLowerCase() === username?.toLowerCase();
        setIsUsernameAvailable(isClaimingSameName || (await validateUsername(name, IS_SUBDOMAIN)));
      } finally {
        setIsValidating(false);
      }
    },
    [validateUsername, username],
  );

  const debouncedValidateUsername = useDebouncedCallback(validateName);

  const handleUsernameChange = useCallback(
    (name: string): void => {
      setIsValidating(true);
      setNewUsername(name);
      debouncedValidateUsername(name);
    },
    [debouncedValidateUsername],
  );

  useLogSubdomainChangeStepViewed();

  usePerfMarkOnMount(PERF_MARKS.subdomain, SUBDOMAIN_MARKS.load_subdomain_change, {
    type: 'end',
  });

  if (isLoading) {
    return (
      <StepWrapper testID="claim-subdomain-change-step">
        <VStack spacingHorizontal={3}>
          <TextTitle1 as="h1" spacingBottom={0.5}>
            {formatMessage(messages.title)}
          </TextTitle1>
          <TextBody as="p" color="foregroundMuted">
            {formatMessage(messages.subtitle)}
          </TextBody>
        </VStack>
        <VStack alignItems="center" justifyContent="center" flexGrow={1}>
          <Spinner testID="change-step-loading-spinner" size={4} color="primary" />
        </VStack>
      </StepWrapper>
    );
  }

  return (
    <StepWrapper testID="claim-subdomain-change-step">
      <VStack spacingHorizontal={3}>
        <TextTitle1 as="h1" spacingBottom={0.5}>
          {formatMessage(messages.title)}
        </TextTitle1>
        <TextBody as="p" color="foregroundMuted">
          {formatMessage(messages.subtitle)}
        </TextBody>
      </VStack>

      <VStack spacingHorizontal={3} spacingTop={3} gap={1} flexGrow={1}>
        <DisabledTransparency>
          <TextInput
            name="current-username"
            disabled
            variant="foregroundMuted"
            label={formatMessage(messages.currentLabel)}
            placeholder={username}
            suffix={subdomainSuffix}
          />
        </DisabledTransparency>
        <ValidatedTextInput
          name="username"
          testID="username-input"
          defaultSubscript={formatMessage(messages.poweredBy)}
          isLoading={isValidating}
          loadingMessage={formatMessage(messages.checking)}
          successMessage={formatMessage(messages.validationAvailable)}
          label={formatMessage(messages.newLabel)}
          value={newUsername}
          onError={setHasErrors}
          autoFocus
          givenError={givenError}
          onChange={handleUsernameChange}
          validators={validators}
          onEnter={handleClaim}
          suffix={subdomainSuffix}
        />
      </VStack>

      <VStack spacingHorizontal={3} spacingBottom={2} gap={1}>
        <TermsCheckbox
          testID="terms-checkbox"
          checked={isTermsChecked}
          onChange={handleTermsChange}
        />
      </VStack>

      <HStack spacingHorizontal={3} spacingBottom={2} gap={1}>
        <Button block variant="secondary" onPress={handleBackPress}>
          {formatMessage(messages.back)}
        </Button>
        <Button
          block
          testID="submit-username-button"
          loading={isClaiming}
          disabled={isDisabled}
          onPress={handleClaim}
        >
          {formatMessage(messages.submit)}
        </Button>
      </HStack>
    </StepWrapper>
  );
});

