export const messages = defineMessages({
  title: {
    defaultMessage: 'Are you sure?',
    description: 'Page title warning of the consequences closing the claiming flow',
  },
  revokeDescription: {
    defaultMessage:
      'You’re allowing other users to claim {subdomain} and will receive a random username like @wallet8emrg60e1zysmz',
    description:
      'Description for warning page that shows when user prematurely exists the claiming flow',
  },
  revokeCheckbox: {
    defaultMessage: 'I understand I am releasing my username @{username} and {subdomain}',
    description: 'Checkbox that insures users know the consequences releasing their username claim',
  },
  revokeClaimButton: {
    defaultMessage: 'I’m sure',
    description: 'Button that confirms users want to release their username claim',
  },
});

export const RevokeStep = memo(function RevokeStep() {
  const activeWalletGroupId = useActiveWalletGroupId();
  const { username, subdomain, revoke } = useSubdomainReservation(activeWalletGroupId);
  const { goBack } = useStepper(stepper);
  const [isReleasingUsername, { toggle: handleReleasingUsername }] = useToggler(false);
  const { formatMessage } = useIntl();

  const formattedMessageValues = useMemo(
    () => ({
      subdomain: <b>{subdomain}</b>,
    }),
    [subdomain],
  );

  const { start: markStartInvalidStepPerf } = useExtensionPerfMark(
    PERF_MARKS.bridge,
    SUBDOMAIN_MARKS.load_subdomain_invalid,
    {
      logMetric: true,
    },
  );

  const handlePress = useCallback(() => {
    markStartInvalidStepPerf();
    goBack();
  }, [goBack, markStartInvalidStepPerf]);

  usePerfMarkOnMount(PERF_MARKS.subdomain, SUBDOMAIN_MARKS.load_subdomain_revoke, {
    type: 'end',
  });

  return (
    <StepWrapper testID="claim-subdomain-revoke-step" overflow="scroll">
      <VStack spacingHorizontal={3} flexGrow={1}>
        <Box spacingBottom={3} flexShrink={1}>
          <Pressable as="button" onPress={handlePress} background="transparent">
            <Icon name="backArrow" size="s" color="foreground" />
          </Pressable>
        </Box>

        <TextTitle1 as="h1" spacingBottom={1}>
          {formatMessage(messages.title)}
        </TextTitle1>

        <TextBody as="p" color="foregroundMuted">
          <FormattedMessage {...messages.revokeDescription} values={formattedMessageValues} />
        </TextBody>
      </VStack>

      <VStack spacingHorizontal={3} gap={2}>
        <Checkbox
          checked={isReleasingUsername}
          onChange={handleReleasingUsername}
          testID="revoke-claim-checkbox"
        >
          <TextLabel2 as="label">
            {formatMessage(messages.revokeCheckbox, { username, subdomain })}
          </TextLabel2>
        </Checkbox>
        <Button block disabled={!isReleasingUsername} onPress={revoke} testID="revoke-claim-cta">
          {formatMessage(messages.revokeClaimButton)}
        </Button>
      </VStack>
    </StepWrapper>
  );
});

