const BUTTON_WIDTH = '60px';

type CollectibleLinkProps = {
  links: CollectibleLink[];
  showButtonText?: boolean;
  transparent?: boolean;
  minWidth?: string | number;
};

export const CollectibleLinkButton = memo(function CollectibleLinkButton({
  links,
  showButtonText = true,
  transparent = false,
  minWidth = BUTTON_WIDTH,
}: CollectibleLinkProps) {
  const { formatMessage } = useIntl();

  const triggerAnalyticsCollectibleOpeninClicked = useCollectibleDetailOpeninClicked();

  const openPopup = useCallback(() => {
    triggerAnalyticsCollectibleOpeninClicked();
  }, [triggerAnalyticsCollectibleOpeninClicked]);

  const onClickHandler = useCallback((url: string) => {
    // Dropdown component fixed the handler signature so we have to parse from url
    let type: LINK_TYPE;
    if (url.toLowerCase().includes('opensea')) {
      type = 'Opensea';
    } else if (url.toLowerCase().includes('rarible')) {
      type = 'Rarible';
    } else if (url.toLowerCase().includes('coinbase')) {
      type = 'Coinbase NFT';
    } else if (url.toLowerCase().includes('polygonscan')) {
      type = 'Polygonscan';
    } else if (url.toLowerCase().includes('solscan')) {
      type = 'Solscan';
    } else {
      type = 'Etherscan';
    }

    triggerCollectibleLinkClicked(type);
    chrome.tabs.create({ url });
  }, []);

  const dropdownContent = useMemo(() => {
    const compactCellSpacing: CellSpacing = { spacingHorizontal: 2, spacingVertical: 2 };

    return (
      <VStack spacing={1}>
        {links.map(({ name: optionType, url, iconUrl }) => {
          return (
            <SelectOption
              key={optionType.toString()}
              value={url}
              title={optionType.toString()}
              innerSpacing={compactCellSpacing}
              outerSpacing={compactCellSpacing}
              borderRadius="rounded"
              media={<CollectibleLinkIcon iconUrl={iconUrl} optionType={optionType} />}
            />
          );
        })}
      </VStack>
    );
  }, [links]);

  return (
    <VStack alignItems="center" minWidth={minWidth}>
      <Dropdown
        onOpenMenu={openPopup}
        onChange={onClickHandler}
        showOverlay
        content={dropdownContent}
      >
        <IconButton
          name="externalLink"
          variant="secondary"
          data-testid="collectible-detail-commerce-open-in-btn"
          transparent={transparent}
        />
      </Dropdown>
      {showButtonText ? (
        <TextLegal as="p" spacingTop={1}>
          {formatMessage(messages.openIn)}
        </TextLegal>
      ) : undefined}
    </VStack>
  );
});

type CollectibleButtonBarProps = {
  sendOnPress?: () => void;
  refreshOnPress: () => void;
  links: CollectibleLink[];
  chainId: string;
  enableRefresh?: boolean;
  collectible: Collectible;
};

export function CollectibleButtonBar({
  sendOnPress,
  refreshOnPress,
  links,
  chainId,
  enableRefresh = true,
  collectible,
}: CollectibleButtonBarProps) {
  const { formatMessage } = useIntl();
  const killNftSend = useIsNFTSendKilled();
  const isNFTSendSupportedForChain = useIsNFTSendSupportedForChainId(chainId);
  const showSendButton = useMemo(() => {
    return !killNftSend && isNFTSendSupportedForChain && sendOnPress && !collectible.isPending;
  }, [collectible.isPending, isNFTSendSupportedForChain, killNftSend, sendOnPress]);

  const showReportButton = useMemo(() => collectible.ownedByWallet, [collectible]);

  const { hideUserCollectible, unhideUserCollectible, hideAndReportSpamCollectible } =
    useHideUserCollectible({
      ...collectible,
      chainId: BigInt(chainId),
    });

  const handleReport = useCallback(() => {
    hideAndReportSpamCollectible('nftdetail');
  }, [hideAndReportSpamCollectible]);

  const { reportAssetAndNavigateAway } = useHideAssetActions({
    onHide: hideUserCollectible,
    onUndo: unhideUserCollectible,
    onReport: handleReport,
    assetName: collectible.name ?? collectible.tokenId,
  });

  return (
    <HStack
      spacingVertical={3}
      spacingHorizontal={6}
      justifyContent={showSendButton ? 'space-between' : 'space-around'}
      background
      testID="collectible-detail-commerce-button-bar"
    >
      {showSendButton ? (
        <CollectibleButton
          onPress={sendOnPress}
          testID="collectible-detail-commerce-send-btn"
          buttonText={formatMessage(messages.send)}
          iconName="upArrow"
          onMount={logSendEntryButtonViewed}
        />
      ) : null}
      {enableRefresh ? (
        <CollectibleButton
          onPress={refreshOnPress}
          testID="collectible-detail-commerce-refresh-btn"
          buttonText={formatMessage(messages.refresh)}
          iconName="refresh"
        />
      ) : null}
      <CollectibleLinkButton links={links} />
      {showReportButton ? (
        <CollectibleButton
          onPress={reportAssetAndNavigateAway}
          testID="collectible-detail-commerce-report-btn"
          buttonText={formatMessage(messages.report)}
          iconName="reportInactive"
        />
      ) : null}
    </HStack>
  );
}

