  })),
}));

const mockHistoryPush = jest.fn();
const refetchWatchlist = jest.fn();
const eventMock = jest.fn();

describe('Watchlist', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockConsoleLog();
    (useGetWatchlist as jest.Mock).mockReturnValue({
      watchlist: mockWatchlistResponse,
      refetchWatchlist,
    });
    (useWatchlistButtonEvent as jest.Mock).mockReturnValue(eventMock);
  });

  afterEach(restoreConsoleLog);

  it('renders', () => {
    renderWithAllProviders(<WatchlistSection />);

    expect(screen.getByText('Watchlist')).toBeInTheDocument();
    expect(screen.getByText('See all')).toBeInTheDocument();

    expect(screen.getByTestId('BTC')).toBeInTheDocument();
    expect(screen.getByTestId('ETH')).toBeInTheDocument();
  });

  it('navigates to watchlist page on see all press', () => {
    renderWithAllProviders(<WatchlistSection />);

    const seeAllPressable = screen.getByTestId('see-all-pressable');
    expect(seeAllPressable).toBeInTheDocument();

    fireEvent.click(seeAllPressable);
    expect(eventMock).toHaveBeenCalledTimes(1);
    expect(mockHistoryPush).toHaveBeenCalledWith('/explore/watchlist');
  });

  it('renders a maximum of 5 watchlist cards', () => {
    const item = watchedItemFactory({});
    const watchlist = Array(6).fill(item);

    (useGetWatchlist as jest.Mock).mockReturnValue({
      watchlist,
      refetchWatchlist,
    });

    renderWithAllProviders(<WatchlistSection />);
    expect(screen.getAllByTestId('BTC')).toHaveLength(5);
