    expect(screen.queryByTestId('watchlist-nux-card')).toBeNull();
    expect(screen.queryByTestId('explore-empty-watchlist-section-loading')).toBeNull();
    expect(screen.queryByTestId('explore-watchlist-section-loading')).toBeNull();
  });

  describe('no watched items', () => {
    it('renders nux card', () => {
      (useGetWatchlist as jest.Mock).mockReturnValue({
        watchlist: undefined,
        refetchWatchlist,
      });

      renderWithAllProviders(<WatchlistSection />);

      const nuxCard = screen.getByTestId('watchlist-nux-card');
      expect(nuxCard).toBeInTheDocument();
    });
  });
});

import { useCallback, useRef } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import {
  logCollectionDetailsCopyAddressClicked,
  logCollectionDetailsOpenInClicked,
} from 'cb-wallet-analytics/collectible';
import { useToast } from 'wallet-cds-extension/overrides/@cbhq/cds-web/overlays/useToast';
import { IconButton } from '@cbhq/cds-web/buttons';
import { Dropdown, DropdownRefProps } from '@cbhq/cds-web/dropdown';
import { Box, HStack } from '@cbhq/cds-web/layout';
import { PopoverContentPositionConfig } from '@cbhq/cds-web/overlays/popover/PopoverProps';

import { CollectionDetailsDropdownContent } from './CollectionDetailsDropdownContent';
import { ExternalLinkDropdownContent } from './ExternalLinkDropdownContent';

const messages = defineMessages({
  copiedContractAddress: {
    defaultMessage: 'Copied contract address',
    description: 'Text shown in toast when user copies contract address',
  },
});

type CollectionDetailsActionsProps = {
  coinbaseLink: string;
  etherscanLink: string;
  raribleLink: string;
  contractAddress: string;
  chainId: string;
};
const dropdownContentPosition: PopoverContentPositionConfig = { placement: 'bottom-end', gap: 2 };

export function CollectionDetailsActions({
  coinbaseLink,
  etherscanLink,
  raribleLink,
  contractAddress,
  chainId,
}: CollectionDetailsActionsProps) {
  const externalDropDownRef = useRef<DropdownRefProps>(null);
  const moreDropDownRef = useRef<DropdownRefProps>(null);

  const { formatMessage } = useIntl();
  const toast = useToast();

  const handleCopyClick = useCallback(() => {
    logCollectionDetailsCopyAddressClicked({ contractAddress, chainId });
    moreDropDownRef.current?.closeMenu();
    navigator.clipboard.writeText(contractAddress);
    toast.show(formatMessage(messages.copiedContractAddress));
  }, [contractAddress, chainId, toast, formatMessage]);

  const handlePressExternal = useCallback(() => {
    logCollectionDetailsOpenInClicked({ contractAddress, chainId });
  }, [contractAddress, chainId]);

  const handleCloseDropdown = useCallback(() => {
    moreDropDownRef.current?.closeMenu();
  }, []);

  return (
    <>
      <HStack gap={0.5}>
        <Dropdown
          key="collection-detail-actions-dropdown"
          ref={externalDropDownRef}
          contentPosition={dropdownContentPosition}
          testID="collection-details-external-links-popover-menu"
          content={
            <ExternalLinkDropdownContent
              coinbaseLink={coinbaseLink}
              etherscanLink={etherscanLink}
              raribleLink={raribleLink}
              contractAddress={contractAddress}
              chainId={chainId}
              closeDropdown={handleCloseDropdown}
            />
          }
        >
          <IconButton
            transparent
            name="externalLink"
            variant="secondary"
            testID="collection-details-external-button"
            onPress={handlePressExternal}
          />
        </Dropdown>
        <Box background="background">
          <Dropdown
            ref={moreDropDownRef}
            contentPosition={dropdownContentPosition}
            testID="collection-details-more-popover-menu"
            content={<CollectionDetailsDropdownContent handleCopyClick={handleCopyClick} />}
          >
            <IconButton
              transparent
              name="more"
              variant="secondary"
              testID="collection-details-menu-button"
            />
          </Dropdown>
        </Box>
      </HStack>
    </>
  );
}

