import { ChangeEvent, memo, useCallback, useState } from 'react';
import { useHistory, useParams } from 'react-router-dom';
import {
  triggerWalletGroupNicknameUpdated,
  useTriggerEditWalletNicknameScreenViewed,
} from 'cb-wallet-analytics/accounts';
import { useEditNicknameCopy } from 'cb-wallet-data/stores/WalletGroups/hooks/useEditNicknameCopy';
import { useUpdateWalletGroupNickname } from 'cb-wallet-data/stores/WalletGroups/hooks/useUpdateWalletGroupNickname';
import { useWalletGroupToDisplay } from 'cb-wallet-data/stores/WalletGroups/hooks/useWalletGroupToDisplay';
import { NavTitle } from 'wallet-cds-extension/components/NavTitle/NavTitle';
import { useToast } from 'wallet-cds-extension/overrides/@cbhq/cds-web/overlays/useToast';
import { Button } from '@cbhq/cds-web/buttons';
import { TextInput } from '@cbhq/cds-web/controls';
import { HStack, VStack } from '@cbhq/cds-web/layout';
import { TextBody, TextTitle1 } from '@cbhq/cds-web/typography';
import { ActionType, ComponentType } from '@cbhq/client-analytics';

export const testID = `edit-nickname`;

export const EditNickname = memo(function EditNickname() {
  const { goBack } = useHistory();
  const { id } = useParams<{ id: string }>();
  const walletGroup = useWalletGroupToDisplay(decodeURIComponent(id));
  const [newNickname, setNewNickname] = useState<string>('');
  const updateWalletGroupNickname = useUpdateWalletGroupNickname();
  const messages = useEditNicknameCopy();
  const toast = useToast();

  useTriggerEditWalletNicknameScreenViewed({
    componentType: ComponentType.page,
    walletIndex: walletGroup?.walletIndex.toString(),
  });

  if (!walletGroup) {
    throw new Error('Wallet group does not exist');
  }

  const handleNicknameInputChange = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      setNewNickname(e.target.value.trim());
    },
    [setNewNickname],
  );

  const handlePressSave = useCallback(async () => {
    try {
      await updateWalletGroupNickname(walletGroup.id, newNickname);
      triggerWalletGroupNicknameUpdated({
        action: ActionType.click,
        componentType: ComponentType.button,
        walletIndex: walletGroup.walletIndex.toString(),
      });
      goBack();
    } catch {
      toast.show(messages.editLabelError);
    }
  }, [goBack, newNickname, walletGroup, updateWalletGroupNickname, toast, messages.editLabelError]);

  return (
    <VStack height="100%" flexGrow={1} overflow="auto">
      <NavTitle />
      <VStack testID={testID} flexGrow={1} spacingHorizontal={2}>
        <VStack gap={4} flexGrow={1}>
          <VStack>
            <TextTitle1 testID={`${testID}--title`} spacingBottom={1} as="h1">
              {messages.editLabelTitle}
            </TextTitle1>
            <TextBody testID={`${testID}--body`} color="foregroundMuted" as="p">
              {messages.editLabelDescription}
            </TextBody>
          </VStack>
          <TextInput
            testID={`${testID}--input`}
            placeholder={messages.placeholder}
            onChange={handleNicknameInputChange}
            label={messages.walletLabel}
          />
        </VStack>
        <HStack gap={1} width="100%">
          <Button testID={`${testID}--save`} block onPress={handlePressSave}>
            {messages.saveButtonLabel}
          </Button>
        </HStack>
      </VStack>
    </VStack>
  );
});

