import { useCallback, useMemo } from 'react';
import {
  useLogAnnouncementCardDismissed,
  useLogAnnouncementCardPressed,
} from 'cb-wallet-analytics/announcements';
import { useLogEventOnMount } from 'cb-wallet-analytics/utils/log';
import { IconButton } from '@cbhq/cds-web/buttons';
import { ListCell } from '@cbhq/cds-web/cells';
import { Box, HStack, VStack } from '@cbhq/cds-web/layout';
import { Pressable } from '@cbhq/cds-web/system';
import { TextLabel1, TextLabel2 } from '@cbhq/cds-web/typography';
import { ActionType, ComponentType } from '@cbhq/client-analytics';

import { Announcement } from '../hooks/useAnnouncements';

type AnnouncementCardProps = {
  announcement: Announcement;
  onDismiss?: (key: string) => void;
};

export function AnnouncementCard({ announcement, onDismiss }: AnnouncementCardProps) {
  const { key, title, description, media, onPress } = announcement;

  const logAnnouncementCardPressed = useLogAnnouncementCardPressed();
  const logAnnouncementCardDismissed = useLogAnnouncementCardDismissed();

  useLogEventOnMount('announcements.card.viewed', {
    loggingId: '8bdcf518-659f-4fc3-af8d-889a18491bc4',
    componentType: ComponentType.banner,
    action: ActionType.view,
    componentName: key,
  });

  const handlePress = useCallback(() => {
    onPress?.();
    logAnnouncementCardPressed({ componentName: key });
  }, [onPress, logAnnouncementCardPressed, key]);

  const handleDismiss = useCallback(() => {
    onDismiss?.(key);
    logAnnouncementCardDismissed({ componentName: key });
  }, [logAnnouncementCardDismissed, onDismiss, key]);

  return useMemo(
    () => (
      <VStack borderedBottom borderedTop testID="wallets-announcements-card" offsetHorizontal={3}>
        <VStack>
          <HStack justifyContent="space-between">
            <Pressable background="transparent" onPress={handlePress} testID="announcement-card">
              <ListCell
                multiline
                title={<TextLabel1 as="p">{title}</TextLabel1>}
                description={
                  <TextLabel2 as="p" color="foregroundMuted">
                    {description}
                  </TextLabel2>
                }
                media={media}
                testID="announcement-card-content"
              />
            </Pressable>
            <Box spacingVertical={1} spacingEnd={1}>
              <IconButton
                testID="announcement-card-dismiss"
                onPress={handleDismiss}
                variant="foregroundMuted"
                name="close"
                transparent
                compact
              />
            </Box>
          </HStack>
        </VStack>
      </VStack>
    ),
    [description, handleDismiss, handlePress, media, title],
  );
}

import { memo, MutableRefObject, useCallback, useMemo, useState } from 'react';
import { useInView } from 'react-intersection-observer';
import { defineMessages, useIntl } from 'react-intl';
import { styled } from '@linaria/react';
import { ETHEREUM_PREFIX } from 'cb-wallet-data/chains/AccountBased/Ethereum/constants';
import { SOLANA_PREFIX } from 'cb-wallet-data/chains/AccountBased/Solana/utils/chain';
import { useIsSolanaCollection } from 'cb-wallet-data/hooks/Collections/useIsSolanaCollection';
import { useCollectionThumbnail } from 'cb-wallet-data/stores/Collection/hooks/useCollectionThumbnail';
import { useIsNFTCollectionSortByChainEnabled } from 'cb-wallet-data/stores/Collection/hooks/useIsNFTCollectionSortByChainEnabled';
import { Collectible, CollectionInfo } from 'cb-wallet-data/stores/Collection/types';
import { Network } from 'cb-wallet-data/stores/Networks/models/Network';
import { CollectibleMedia } from 'wallet-cds-web/components/CollectibleMedia';
import { isMediaInfoCached } from 'wallet-cds-web/components/CollectibleMedia/hooks/useMediaInfo';
import { NetworkIcon } from 'wallet-cds-web/components/NetworkIcon';
import { ListCell } from '@cbhq/cds-web/cells';
import { Collapsible } from '@cbhq/cds-web/collapsible';
import { Icon } from '@cbhq/cds-web/icons/Icon';
import { Box, Fallback, HStack, VStack } from '@cbhq/cds-web/layout';
import { TextLabel2 } from '@cbhq/cds-web/typography';

import { CollectiblesListV2 } from ':extension/screens/PortfolioCollection/CollectiblesListV2';

import { CollectionItemOverlay } from './CollectionItemOverlay';
import { COLLECTIBLE_BLOCK_PADDING, COLLECTIBLE_BLOCK_WIDTH } from './constants';

export const messages = defineMessages({
  collectionAccessibilityLabel: {
    defaultMessage: 'Collection {collectionName}',
    description: 'Accessibility label for an NFT collection header',
  },
});

// avatar icon size
const ICON_SIZE = 32;
// root margin for intersection observer to prefetch
const PREFTECH_BOUNDARY_MARGIN_COLLECTIONS_LIST_ITEM = '400px 0px';

type Props = {
  collectionInfo: CollectionInfo;
  tokens: Collectible[];
  onPress: () => void;
  onMediaLoadSuccess?: (chainId?: string) => void;
  containerRef?: MutableRefObject<Element | null>;
  collapsed?: boolean;
  actionTile?: React.ReactNode;
};

function CollectionsListItemV2Component({
  collectionInfo,
  tokens,
  onPress,
  onMediaLoadSuccess,
  containerRef,
  collapsed,
  actionTile,
}: Props) {
  const { formatMessage } = useIntl();
  const collectibles = tokens || [];
  const firstCollectible = collectibles[0] || {};
  const collectionThumbnailDetails = useCollectionThumbnail({
    collectionInfo,
    token: firstCollectible,
  });

  const count = useMemo(
    () => tokens.reduce((acc, listInfo) => acc + Number.parseInt(listInfo.tokenCount), 0),
    [tokens],
  );

  // maintain which list items are in view so that we can conditionally load
  const { ref, inView } = useInView({
    rootMargin: PREFTECH_BOUNDARY_MARGIN_COLLECTIONS_LIST_ITEM, // stagger loading for list item avatar (first collectible image)
    root: containerRef?.current, // defaults to body if none is provided,
  });

  const handlePress = useCallback(() => {
    onPress();
  }, [onPress]);

  const [mediaLoaded, setMediaLoaded] = useState(isMediaInfoCached(firstCollectible));

  const handleMediaLoadSuccess = useCallback(
    (chainId?: string) => {
      onMediaLoadSuccess?.(chainId || '');
      setMediaLoaded(true);
    },
    [onMediaLoadSuccess],
  );

  const handleMediaLoad = useCallback(() => {
    setMediaLoaded(true);
  }, []);

  const rowCount = Math.ceil(collectibles.length / 3);
  // dimensons for the block element used to represent the collectibles list for a collection
  const height = rowCount * COLLECTIBLE_BLOCK_WIDTH + (rowCount - 1) * COLLECTIBLE_BLOCK_PADDING;
  const len = collectibles.length;
  const width = `${
    COLLECTIBLE_BLOCK_WIDTH * Math.min(3, len) + COLLECTIBLE_BLOCK_PADDING * Math.min(2, len - 1)
  }px`;

  const isSolanaCollection = useIsSolanaCollection({
    chainId: collectionInfo.chainId,
    tokenType: collectibles[0]?.tokenType,
  });
  const chainPrefix = isSolanaCollection ? SOLANA_PREFIX : ETHEREUM_PREFIX;
  const network = Network.fromChainId({
    chainId: BigInt(collectionInfo.chainId),
    chainPrefix,
  });

  const isCollectionSortingEnabled = useIsNFTCollectionSortByChainEnabled();

  return (
    <VStack ref={ref} testID={`nft-collection-${collectionInfo.contractAddress}`}>
      <>
        <ListCell
          testID="collections-list-item-cell"
          title={collectionInfo.collectionName}
          media={
            // List cell avatar is either an image (if in view) or a fallback item
            inView || mediaLoaded ? (
              <Box>
                <CollectionItemOverlay width={ICON_SIZE} height={ICON_SIZE} shape="squircle" />
                <CollectibleMedia
                  testID="avatar-media"
                  height={`${ICON_SIZE}px`}
                  width={`${ICON_SIZE}px`}
                  radius="rounded"
                  dangerouslySetRadius="8px"
                  preview
                  contractAddress={collectionInfo.contractAddress}
                  {...collectionThumbnailDetails}
                  onMediaLoadSuccess={handleMediaLoadSuccess}
                  onMediaLoadFailure={handleMediaLoad}
                  emptyVariant="avatar"
                  chainId={collectionInfo.chainId.toString()}
                  accessibilityLabel={formatMessage(messages.collectionAccessibilityLabel, {
                    collectionName: collectionInfo.collectionName || '',
                  })}
                />
                {isCollectionSortingEnabled && network && (
                  <Box position="absolute" width={ICON_SIZE + 6} height={ICON_SIZE + 1} zIndex={4}>
                    <Box position="absolute" bottom={0} right={0}>
                      <NetworkIcon
                        network={network}
                        size="small"
                        bordered
                        testID="collections-list-item-network-icon"
                      />
                    </Box>
                  </Box>
                )}
              </Box>
            ) : (
              <Fallback
                testID="loading-list-item"
                width={ICON_SIZE}
                height={ICON_SIZE}
                shape="squircle"
              />
            )
          }
          detail={
            <HStack gap={1} justifyContent="flex-end" spacingStart={6} alignItems="center">
              <span style={{ visibility: collapsed ? 'visible' : 'hidden' }}>
                <TextLabel2 align="center" as="p" color="foregroundMuted" testID="tokens-count">
                  {count}
                </TextLabel2>
              </span>
              <Rotate collapsed={!!collapsed}>
                <Icon name="caretDown" size="s" color="foreground" />
              </Rotate>
            </HStack>
          }
          onPress={handlePress}
          priority="end"
        />
        {/*
          Below is the collapsible content that contains collectibles within a collection. Render if the collection
          is visible. If not within viewport, then render a single block element that is the same dimensions as the list
          if it were rendered. This minimizes dom elements on the page, and speeds up load and collapse of each row.
        */}
        {!inView || (!rowCount && !actionTile) ? (
          <div
            data-testid="placeholder-block"
            style={{
              width,
              height: `${collapsed ? '0px' : height}px`,
              backgroundColor: 'rgb(var(--gray80))',
              opacity: 0.03,
              marginLeft: '24px',
            }}
          />
        ) : (
          <Collapsible
            collapsed={!!collapsed}
            dangerouslyDisableOverflowHidden
            testID="collapsible-content"
          >
            <VStack width="100%">
              <CollectiblesListV2
                collectionName={collectionInfo.collectionName}
                containerRef={containerRef}
                collectibles={collectibles}
                visible={!collapsed && inView}
                onMediaLoadSuccess={onMediaLoadSuccess}
                chainId={collectionInfo.chainId.toString()}
              />
              {actionTile}
            </VStack>
          </Collapsible>
        )}
      </>
    </VStack>
  );
}

// NOTE: Not using CollapseArrow because it does not allow for color-selection
const Rotate = styled.div<{ collapsed: boolean }>`
  transform: ${({ collapsed }) => (collapsed ? 'rotate(180deg)' : 'rotate(0deg)')};
  transition: transform 0.2s linear;
`;

export const CollectionsListItemV2 = memo(CollectionsListItemV2Component);

import { memo, useCallback } from 'react';
import { logDappAutoConnectStart } from 'cb-wallet-analytics/dapp';
import { v4 as uuidv4 } from 'uuid';
import { ErrorBoundary } from 'wallet-cds-web/components/ErrorBoundary';
import { Icon } from '@cbhq/cds-web/icons';
import { Box } from '@cbhq/cds-web/layout';
import { Pressable } from '@cbhq/cds-web/system';

import {
  useAddDappConnections,
  useGetConnectionResponse,
} from ':extension/hooks/useGetConnectionResponseAndAddDappConnections/useGetConnectionResponseAndAddDappConnections';
import { useWalletsForWalletConnection } from ':extension/hooks/useWalletsForWalletConnection/useWalletsForWalletConnection';
import { isProd } from ':extension/util/isProd';

export const testID = 'portfolio-header';

function DappLinkout() {
  const wallets = useWalletsForWalletConnection();
  const getDappConnectionResponsesForWallets = useGetConnectionResponse();
  const addDappConnectionsForWallets = useAddDappConnections();

  const handleAutoConnect = useCallback(async () => {
    const source = 'extension';
    const requestId = uuidv4();

    logDappAutoConnectStart(source, requestId);

    const baseURL = isProd() ? 'https://wallet.coinbase.com' : 'http://localhost:3000';

    const response = await getDappConnectionResponsesForWallets({
      wallets,
    });

    await addDappConnectionsForWallets({
      accountResponse: response.account!,
      dappName: 'Panorama',
      dappLogoURL: baseURL,
      dappURL: baseURL,
      dappLogoURLAlt: '',
    });

    await chrome.runtime.sendMessage({
      source,
      requestId,
      type: 'wallet-beta-autoconnect',
      url: `${baseURL}/view`,
      data: {
        connectionResponse: response,
      },
    });
  }, [addDappConnectionsForWallets, getDappConnectionResponsesForWallets, wallets]);

  return (
    <Box spacingStart={1}>
      <Pressable onPress={handleAutoConnect} background="transparent" testID="dapp-linkout">
        <Icon name="expandAll" size="s" color="foreground" testID="notification-bell-icon" />
      </Pressable>
    </Box>
  );
}

const DappLinkoutWithBoundary = memo(function DappLinkoutWithBoundary() {
  return (
    <ErrorBoundary>
      <DappLinkout />
    </ErrorBoundary>
  );
});

export { DappLinkoutWithBoundary as DappLinkout };

import { memo, useCallback, useEffect, useMemo, useRef } from 'react';
import { useInView } from 'react-intersection-observer';
import { AutoSizer, List, ListRowProps, WindowScroller } from 'react-virtualized';
import { countString } from 'cb-wallet-data/stores/Collection/hooks/useWalletCollectiblesSizeEventTag';
import { PortfolioCollectible } from 'cb-wallet-data/stores/Collection/types';
import { CollectibleMedia } from 'wallet-cds-web/components/CollectibleMedia';
import { Box, HStack, VStack } from '@cbhq/cds-web/layout';
import { Pressable } from '@cbhq/cds-web/system';

import {
  COLLECTIBLE_BLOCK_PADDING,
  COLLECTIBLE_BLOCK_WIDTH,
} from ':extension/screens/Portfolio/CollectionsPortfolio/constants';
import { useCollectiblePerfMarks } from ':extension/screens/Portfolio/CollectionsPortfolio/hooks/useCollectiblePerfMarks';

import { CollectibleGridItemBadge } from './CollectibleGridItemBadge';
import { COLLECTIBLE_ASSET_WIDTH, COLLECTIBLES_PER_ROW } from './PaginatedCollectionTokens';

const LIST_CONTAINER_SELECTOR = '[data-testid="portfolio-component"]';

type CollectibleGridProps = {
  tokens: PortfolioCollectible[];
  isFetching: boolean;
  onEndReached: () => void;
  onPressCollectibleListItem: (collectible: PortfolioCollectible) => () => void;
  scrollElement?: Element;
};

export const CollectibleGrid = memo(function CollectibleGrid({
  tokens,
  isFetching,
  onEndReached,
  onPressCollectibleListItem,
  scrollElement,
}: CollectibleGridProps) {
  const container = useRef<List>(null);

  const loadedFirstCollectible = useRef(false);
  const totalCollectiblesCount = countString(tokens.length);

  const { endCollectiblePerfMark: endLoadFirstCollectiblePerfMark } = useCollectiblePerfMarks(
    'nft_grid_view',
    'load_first_collectible',
    {
      tags: {
        totalCollectiblesCount,
      },
    },
  );

  useEffect(
    function resizeList() {
      container.current?.forceUpdateGrid();
    },
    [container],
  );

  // redraw grid on collection update
  useEffect(
    function updateList() {
      container.current?.recomputeRowHeights(0);
      container.current?.forceUpdateGrid();
    },
    [tokens],
  );

  const containerRef = useRef(document.querySelector(LIST_CONTAINER_SELECTOR));
  useEffect(function getRef() {
    containerRef.current = document.querySelector(LIST_CONTAINER_SELECTOR);
  }, []);

  const { ref: fetchMoreElement, inView: fetchMoreElementInView } = useInView({
    initialInView: false,
  });

  useEffect(
    function fetchMoreInView() {
      if (fetchMoreElementInView && !isFetching) {
        onEndReached?.();
      }
    },
    [fetchMoreElementInView, onEndReached, isFetching],
  );

  const handleMediaLoadSuccess = useCallback(() => {
    if (!loadedFirstCollectible.current) {
      endLoadFirstCollectiblePerfMark();
      loadedFirstCollectible.current = true;
    }
  }, [endLoadFirstCollectiblePerfMark]);

  const handleRowRender = useCallback(
    ({ key, index, style }: ListRowProps) => {
      // we can't have a virtualized list within a virtualized list so we need to use element refs
      // to determine if we need to fetch a new page - fetching when 2nd to last element is in view
      // to minimize rendering delay
      const elementRef =
        index === Math.max(0, Math.ceil(tokens.length / COLLECTIBLES_PER_ROW) - 3) && !isFetching
          ? fetchMoreElement
          : null;

      const items = [];
      const fromIndex = index * COLLECTIBLES_PER_ROW;
      const toIndex = Math.min(fromIndex + COLLECTIBLES_PER_ROW, tokens.length);

      for (let i = fromIndex; i < toIndex; i++) {
        if (tokens[i]) {
          const token = tokens[i];

          items.push(
            <Pressable
              testID={`token-row-asset-${token.id}`}
              key={token.id}
              background="transparent"
              onPress={onPressCollectibleListItem(token)}
            >
              <Box spacingBottom={3}>
                <CollectibleMedia
                  {...token}
                  height={`${COLLECTIBLE_ASSET_WIDTH}px`}
                  width={`${COLLECTIBLE_ASSET_WIDTH}px`}
                  contractAddress={token.contractAddress}
                  radius="roundedLarge"
                  chainId={token.chainId}
                  preview
                  hasBackground
                  imageUrl={token?.media?.image?.originalUrl}
                  cachedImageUrl={token?.media?.image}
                  animationUrl={token?.media?.animation?.originalUrl}
                  cachedAnimationUrl={token?.media?.animation}
                  onMediaLoadSuccess={handleMediaLoadSuccess} // TODO
                  resizeMode="cover"
                  hasUnretrievableMetadata={token?.hasUnretrievableMetadata}
                />
                <CollectibleGridItemBadge
                  isPending={token.isPending}
                  oe721Count={token.oe721Count}
                />
              </Box>
            </Pressable>,
          );
        }
      }

      return (
        <HStack
          ref={elementRef}
          key={key}
          testID="generic-collection-list-row"
          justifyContent={items.length === COLLECTIBLES_PER_ROW ? 'space-between' : 'flex-start'}
          spacingHorizontal={1}
          style={style}
          gap={1}
        >
          {items}
        </HStack>
      );
    },
    [tokens, isFetching, fetchMoreElement, onPressCollectibleListItem, handleMediaLoadSuccess],
  );

  const rowCount = useMemo(() => Math.ceil(tokens.length / COLLECTIBLES_PER_ROW), [tokens.length]);
  const rowHeight = useMemo(() => COLLECTIBLE_BLOCK_WIDTH + COLLECTIBLE_BLOCK_PADDING + 2, []);

  return (
    <VStack spacingHorizontal={2} flexGrow={1} testID="collectible-grid">
      <WindowScroller scrollElement={scrollElement}>
        {({ scrollTop }) => (
          <AutoSizer disableHeight>
            {({ width, height }) => (
              <List
                ref={container}
                autoHeight
                rowCount={rowCount}
                width={width || 345}
                height={height || 500}
                rowHeight={rowHeight}
                overscanRowCount={10}
                rowRenderer={handleRowRender}
                scrollTop={scrollTop}
              />
            )}
          </AutoSizer>
        )}
      </WindowScroller>
    </VStack>
  );
});

