  logProfileFollowingCopyClicked,
  logProfileFollowingUnfollowClicked,
  ProfileEventData,
} from ':extension/screens/Profile/utils/ProfileAnalytics';

type ProfileListItemMenuProps = {
  address: string;
} & ProfileFollowActionProps;

const messages = defineMessages({
  copyMenuItemTitle: {
    defaultMessage: 'Copy',
    description: 'Title for copy menu item',
  },
  copyMenuItemDescription: {
    defaultMessage: 'Copy this address',
    description: 'Description for copy menu item',
  },
  unfollowMenuItemTitle: {
    defaultMessage: 'Unfollow',
    description: 'Title for unfollow menu item',
  },
  unfollowMenuItemDescription: {
    defaultMessage: 'Unfollow this address',
    description: 'Description for unfollow menu item',
  },
});

export function ProfileListItemMenu({ address, onUnfollow }: ProfileListItemMenuProps) {
  const { formatMessage } = useIntl();
  const copyToClipboard = useClipboard();
  const activeWalletGroupId = useActiveWalletGroupId();
  const profileAddress = useProfileAddress(activeWalletGroupId);
  const deleteFollow = useDeleteFollow(profileAddress);

  const eventData: ProfileEventData = useMemo(() => {
    return {
      walletAddress: address,
      chainName: 'eth',
    };
  }, [address]);

  const copyAddress = useCallback(() => {
    logProfileFollowingCopyClicked(eventData);
    copyToClipboard(address);
  }, [address, copyToClipboard, eventData]);

  const unfollow = useCallback(async () => {
    logProfileFollowingUnfollowClicked(eventData);
    const response = await deleteFollow(address);
    onUnfollow?.(response);
  }, [address, onUnfollow, deleteFollow, eventData]);

  return (
    <Dropdown
      width={300}
      content={
        <>
          <MenuItem value="Copy" onPress={copyAddress}>
            <ListCell
              title={formatMessage(messages.copyMenuItemTitle)}
              description={formatMessage(messages.copyMenuItemDescription)}
              media={<Icon name="copy" size="m" />}
            />
          </MenuItem>
          <MenuItem value="Unfollow" onPress={unfollow}>
            <ListCell
              title={formatMessage(messages.unfollowMenuItemTitle)}
              description={formatMessage(messages.unfollowMenuItemDescription)}
              media={<Icon name="circleCross" size="m" />}
            />
          </MenuItem>
        </>
      }
    >
      <IconButton name="more" variant="secondary" />
    </Dropdown>
  );
}

