export const ProfileFollowInfo = memo(function ProfileFollowInfo() {
  const { goBack } = useHistory();
  const { query } = useParams<ProfilePageParams>();
  const activeWalletGroupId = useActiveWalletGroupId();
  const { followee, follower, title } = useProfileDetails(activeWalletGroupId, query);

  return (
    <VStack height="100%">
      <VStack spacingHorizontal={1}>
        <NavTitle onBack={goBack} title={title} />
      </VStack>

      <Box spacingHorizontal={3}>
        <ProfileFollowInfoSelector query={query} followerAddress={follower.address} />
      </Box>

      <Switch>
        <Route exact path={`/profile/${query}/follow-info/followers`}>
          <ProfileFollowers address={followee.address} />
        </Route>
        <Route exact path={`/profile/${query}/follow-info/following`}>
          <ProfileFollowees address={followee.address} />
        </Route>
      </Switch>
    </VStack>
  );
});

