type BoxPropsSubset = Partial<
  Omit<
    React.ComponentProps<typeof Box>,
    | 'bordered'
    | 'borderRadius'
    | 'flexDirection'
    | 'spacingTop'
    | 'spacingBottom'
    | 'spacingStart'
    | 'spacingEnd'
  >
>;

type ReceiveWalletAddressListItemProps = BoxPropsSubset & {
  blockchainName: AllPossibleBlockchainSymbol;
  walletAddress: WalletAddress;
  onPressCopy: (blockchainName: AllPossibleBlockchainSymbol, walletAddress: WalletAddress) => void;
  onPressQRCode: (
    blockchainName: AllPossibleBlockchainSymbol,
    walletAddress: WalletAddress,
  ) => void;
};

export function ReceiveWalletAddressListItem(props: ReceiveWalletAddressListItemProps) {
  const { onPressCopy, onPressQRCode, blockchainName, walletAddress, ...otherBoxProps } = props;
  const {
    address,
    type: { rawValue: addressType },
  } = walletAddress;
  const wallets = usePrimaryReceiveWallets();

  const wallet = useMemo(() => {
    return wallets.get(blockchainName);
  }, [blockchainName, wallets]);
  const { formatMessage } = useIntl();
  const { activeEthMainnets, activeSolMainnets } = useActiveNetworks();
  const isNetworkAllowed = useIsNetworkAllowed();

  const { headlineMessage, addressTooltipMessage } = useMemo<
    Record<string, Omit<MessageDescriptor, 'id'>>
  >(() => {
    switch (addressType) {
      case SolanaAddressType.rawValue:
        return {
          headlineMessage: messages.solAddressHeadline,
          addressTooltipMessage: messages.solAddressLabelTooltip,
        };

      case BitcoinSegwitAddressType.rawValue:
        return {
          headlineMessage: messages.btcAddressHeadline,
          addressTooltipMessage: messages.btcAddressLabelTooltip,
        };

      case DogecoinAddressType.rawValue:
        return {
          headlineMessage: messages.dogeAddressHeadline,
          addressTooltipMessage: messages.dogeAddressLabelTooltip,
        };
      case LitecoinSegwitAddressType.rawValue:
        return {
          headlineMessage: messages.ltcAddressHeadline,
          addressTooltipMessage: messages.ltcAddressLabelTooltip,
        };
      default:
        return {
          headlineMessage: messages.ethAddressHeadline,
          addressTooltipMessage: messages.ethAddressLabelTooltip,
        };
    }
  }, [addressType]);

  const supportedChainIcons = useMemo<JSX.Element[]>(() => {
    let networks: { name: string; network: Network }[] = [];

    switch (addressType) {
      case SolanaAddressType.rawValue:
        networks = activeSolMainnets;
        break;
      case BitcoinSegwitAddressType.rawValue:
        return [
          <NetworkIcon
            size="small"
            key={addressType}
            network={BitcoinWalletConfiguration.networkSetting.defaultMainnet.network}
            assetIconUrl={BitcoinWalletConfiguration.imageURL}
          />,
        ];
      case DogecoinAddressType.rawValue:
        return [
          <NetworkIcon
            size="small"
            key={addressType}
            network={DogecoinWalletConfiguration.networkSetting.defaultMainnet.network}
            assetIconUrl={DogecoinWalletConfiguration.imageURL}
          />,
        ];
      case LitecoinSegwitAddressType.rawValue:
        return [
          <NetworkIcon
            size="small"
            key={addressType}
            network={LitecoinWalletConfiguration.networkSetting.defaultMainnet.network}
            assetIconUrl={LitecoinWalletConfiguration.imageURL}
          />,
        ];
      default:
        networks = activeEthMainnets;
    }

    networks = networks
      .filter((network) => {
        const shouldShowIcon = SUPPORTED_ACCOUNT_BASED_ADDRESS_TYPE_NETWORK_ICONS.get(
          addressType,
        )?.includes(network.name);
        const isAllowed = isNetworkAllowed(network.network);
        return shouldShowIcon && isAllowed;
      })
      .sort(sortNetworksWithPrioritization);

    return networks.map((network) => (
      <NetworkIcon network={network.network} size="small" key={network.name} />
    ));
  }, [addressType, activeSolMainnets, activeEthMainnets, isNetworkAllowed]);

  const handlePressCopy = useCallback<
    NonNullable<React.ComponentProps<typeof IconButton>['onPress']>
  >(() => {
    triggerReceiveByGenericCopyAddressClicked(blockchainName);
    navigator.clipboard?.writeText?.(address);
    onPressCopy(blockchainName, walletAddress);
  }, [blockchainName, address, onPressCopy, walletAddress]);

  const handlePressQRCode = useCallback<
    NonNullable<React.ComponentProps<typeof IconButton>['onPress']>
  >(() => {
    triggerReceiveByGenericQrCodeClicked(blockchainName);
    onPressQRCode(blockchainName, walletAddress);
  }, [onPressQRCode, blockchainName, walletAddress]);

  return (
    <Pressable onPress={handlePressCopy} background="transparent">
      <Box
        {...otherBoxProps}
        bordered
        borderRadius="rounded"
        flexDirection="column"
        background="transparent"
        spacingTop={2}
        spacingBottom={2}
        spacingStart={2}
        spacingEnd={2}
      >
        <HStack gap={1} alignItems="center" spacingBottom={0.5}>
          <TextHeadline as="p" testID="wallet-address-headline">
            {formatMessage(headlineMessage)}
          </TextHeadline>
          <Tooltip content={formatMessage(addressTooltipMessage)} placement="bottom">
            <Icon name="info" size="xs" color="foreground" />
          </Tooltip>
        </HStack>

        <HStack justifyContent="space-between" gap={2}>
          <VStack>
            <TextLabel2 as="p" color="foregroundMuted" testID="wallet-address-string">
              <span className={breakWord}>
                {wallet ? address : formatMessage(messages.scanningAddresses)}
              </span>
            </TextLabel2>

            {Boolean(supportedChainIcons.length) && (
              <VStack>
                <Spacer vertical={0.5} />
                <HStack gap={1} testID="wallet-address-chain-icons">
                  {supportedChainIcons}
                </HStack>
              </VStack>
            )}
          </VStack>
          <HStack gap={1}>
            <IconButton
              // @ts-expect-error TS(2322): Type 'string' is not assignable to type 'Component... Remove this comment to see the full error message
              as="div"
              name="qrCode"
              onPress={handlePressQRCode}
              testID="wallet-address-qr-code-button"
            />
            <CopyIconButton
              // @ts-expect-error TS(2322): Type 'string' is not assignable to type 'Component... Remove this comment to see the full error message
              as="div"
              textToCopy={address}
              testID="wallet-address-copy-button"
            />
          </HStack>
        </HStack>
      </Box>
    </Pressable>
  );
}

import { useCallback, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { useSearchReceiveAssetViewed } from 'cb-wallet-analytics/receive';
import { useDebouncedCallback } from 'cb-wallet-data/hooks/useDebouncedCallback';
