import { TextInput } from '@cbhq/cds-web/controls';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import { TextBody, TextLabel2, TextTitle3 } from '@cbhq/cds-web/typography';

import { form, stepper } from ':extension/screens/Send/flow';

const messages = defineMessages({
  title: {
    defaultMessage: 'Select send amount',
    description: 'Title for Collectible Amount page',
  },
  heading: {
    defaultMessage: 'Select amount to send',
    description: 'Heading displayed in the screen content',
  },
  subHeading: {
    defaultMessage: 'You have multiple copies of this asset. How many would you like to send?',
    description: 'Sub-heading displayed in the screen content',
  },
  amountInputLabel: {
    defaultMessage: 'Send amount',
    description: 'Label of the input component for inputting send amount',
  },
  amountInputHelperText: {
    defaultMessage: 'You can send up to {amount}',
    description: 'Helper text of the input component for inputting send amount',
  },
  primaryButton: {
    defaultMessage: 'Continue',
    description: 'Text for primary button in the screen to proceed',
  },
});

export function CollectibleAmountStep() {
  const history = useHistory();
  const { tokenCount } = useParams<{ tokenCount: string }>();
  const { formatMessage } = useIntl();
  const { goToStep, goBack: goBackOneStep, previousStep } = useStepper(stepper);
  const { collectibleAmount } = useFields(form);
  const [inputValue, setInputValue] = useState('1');
  const { onChange: formCollectibleAmountOnChange } = collectibleAmount;

  const isValidAmountInputValue = useMemo(() => {
    if (!inputValue.match(/^[1-9]\d*$/)) {
      return false;
    }
    const inputValueBN = BigInt(inputValue);
    return inputValueBN >= BigInt(1) && inputValueBN <= BigInt(tokenCount);
  }, [inputValue, tokenCount]);

  const goBack = useCallback(() => {
    if (previousStep === undefined) {
      history.goBack();
    } else {
      goBackOneStep();
    }
  }, [goBackOneStep, previousStep, history]);

  const handleAmountInputChange = useCallback((e: ChangeEvent<HTMLInputElement>) => {
    setInputValue(e.target.value);
  }, []);

  const handleSubmit = useCallback(() => {
    if (!isValidAmountInputValue) {
      return;
    }
    formCollectibleAmountOnChange(BigInt(inputValue));
    goToStep('selectRecipient');
  }, [formCollectibleAmountOnChange, inputValue, isValidAmountInputValue, goToStep]);

  return (
    <VStack height={DEFAULT_VIEWPORT_HEIGHT}>
      <NavTitle onBack={goBack} title={formatMessage(messages.title)} />
      <VStack justifyContent="space-between" spacingHorizontal={3}>
        <VStack alignContent="center" minHeight="370">
          <TextTitle3 as="h2">{formatMessage(messages.heading)}</TextTitle3>
          <TextBody as="p" color="foregroundMuted" spacingTop={1} spacingBottom={3}>
            {formatMessage(messages.subHeading)}
          </TextBody>
          <TextInput
            value={inputValue}
            testID="amount-input"
            label={formatMessage(messages.amountInputLabel)}
            onChange={handleAmountInputChange}
            variant={!isValidAmountInputValue ? 'negative' : undefined}
            autoComplete="off"
          />
          <TextLabel2 as="p" color="foregroundMuted" spacingTop={0.5} spacingStart={1}>
            {formatMessage(messages.amountInputHelperText, {
              amount: tokenCount,
            })}
          </TextLabel2>
        </VStack>
        <Button disabled={!isValidAmountInputValue} onPress={handleSubmit}>
          {formatMessage(messages.primaryButton)}
        </Button>
      </VStack>
    </VStack>
  );
}

