export function SendConfirmation({ wallet }: ConfirmationStepProps) {
  const { formatMessage } = useIntl();
  const { goToStep, goBack: goBackOneStep, previousStep } = useStepper(stepper);
  const history = useHistory();
  const {
    toAddress,
    cryptoAmount,
    unsignedTxResult,
    txSigningError,
    signedTx: formSignedTx,
    searchQuery,
    destinationType,
    lastGasPreset,
    isGaslessRelayDisabled,
  } = useFields(form);
  const { walletType, hasLocallyStoredKey, isLedgerAccount } = useAccountById(wallet.accountId);
  const [lastUpdateTime, setLastUpdateTime] = useState(new Date());
  const [isRecalculatingFees, setIsRecalculatingFees] = useState(false);
  const currencyFormatter = useCurrencyFormatter();
  const saveRecentRecipient = useSaveRecentRecipient();

  const isRealTimeGasFeeEnabled = useIsRealTimeGasFeesEnabled(wallet);
  const isSendConfirmationSpamTokenWarningEnabled = useIsSendSpamTokenWarningEnabled();

  const shouldShowSpamTokenWarning = useMemo(() => {
    const isSpamToken = wallet.isSpam;
    const networkChain = wallet.network.asChain();
    const chainId = networkChain ? BigInt(networkChain.chainId) : undefined;
    const isSpamTokenWarningEnabled = isSendConfirmationSpamTokenWarningEnabled(chainId);

    return isSpamToken && isSpamTokenWarningEnabled;
  }, [isSendConfirmationSpamTokenWarningEnabled, wallet.isSpam, wallet.network]);

  const warning = useMemo(() => {
    if (shouldShowSpamTokenWarning) {
      return (
        <VStack>
          <TextHeadline as="p" spacingStart={1} tabIndex={0}>
            {formatMessage(messages.sendSpamTokenWarningTitle)}
          </TextHeadline>
          <TextBody as="p" color="foregroundMuted" spacingStart={1} tabIndex={0}>
            {formatMessage(messages.sendSpamTokenWarningDescription)}{' '}
          </TextBody>
        </VStack>
      );
    }
  }, [formatMessage, shouldShowSpamTokenWarning]);

  const unsignedTx = unsignedTxResult.value!;
  const onChangeUnsignedTx = unsignedTxResult.onChange;

  const analyticsFeeData = useAnalyticsFeeData(unsignedTx.transaction, wallet);
  const isSponsoredTx = Boolean(useGetSponsoredSendInfo(wallet));
  const isSponsoredAndRelayEnabled = useCallback(
    () => isSponsoredTx && !isGaslessRelayDisabled.value,
    [isGaslessRelayDisabled.value, isSponsoredTx],
  );

  const {
    currentSendTab: { value: sendType },
  } = useFields(form);
  const collectibleChainId = useCollectibleChainId();
  const triggerAnalyticsSendClicked = useSendConfirmationSendClicked({
    sendType,
    collectibleChainId,
    blockchain: wallet.blockchain.rawValue,
    chainId: wallet.network.asChain()?.chainId,
    chainName: wallet.network.asChain()?.displayName,
    currencyCode: wallet.currencyCode.code,
    contractAddress: wallet.contractAddress,
    isSponsoredTx: isSponsoredAndRelayEnabled(),
  });
  const triggerAnalyticsCancelClicked = useSendConfirmationCancelClicked();
  const triggerAnalyticsGasFeeNotShown = useSendConfirmationGasFeeNotShown();
  const triggerConfirmationGasFeeViewed1559 = useTriggerConfirmationGasFeeViewed1559();
  const triggerConfirmationSolNetworkFeeViewed = useTriggerConfirmationSolNetworkFeeViewed();
  const realTimeGasFeesParams = useMemo(
    () => ({
      blockchain: wallet.blockchain.rawValue,
      isBaseAsset: wallet.isBaseAsset,
      is1559NetworkEnabled: isNetwork1559Enabled(wallet.network),
    }),
    [wallet.blockchain.rawValue, wallet.isBaseAsset, wallet.network],
  );

  const triggerSendGasFeeRefreshed = useSendRealTimeGasFeesRefreshSucceed(realTimeGasFeesParams);
  const triggerSendGasFeeFailed = useSendRealTimeGasFeesRefreshFailed(realTimeGasFeesParams);

  const { onChange: forTxSigningErrorOnChange } = txSigningError;
  const { onChange: updateIsGaslessRelayDisabled } = isGaslessRelayDisabled;
  const blockchainName = wallet.blockchain.toString();

  useOnMount(function resetGasPreset() {
    return () => {
      lastGasPreset.onChange(undefined);
    };
  });

  const signError = useCallback(
    (error: Error) => {
      forTxSigningErrorOnChange(error);
      goToStep('status');
    },
    [goToStep, forTxSigningErrorOnChange],
  );

  const signLedgerError = useCallback(
    (error: Error) => {
      cbReportError({
        error: new Error(error.message),
        context: 'ledger-error',
        severity: 'error',
        isHandled: false,
      });
      signError(error);
    },
    [signError],
  );

  const signSuccess = useCallback(
    // TODO (Justin): Make signedTx a required param and update the param types to account for it
    // https://jira.coinbase-corp.com/browse/WALL-37697
    (signedTx?: SignedTx) => {
      formSignedTx.onChange(signedTx as Transaction);
      const domain = searchQuery.value !== toAddress.value ? searchQuery.value : undefined;
      saveRecentRecipient(toAddress.value, wallet.blockchain, domain);
      goToStep('status');
    },
    [
      goToStep,
      saveRecentRecipient,
      searchQuery.value,
      formSignedTx,
      toAddress.value,
      wallet.blockchain,
    ],
  );

  const onSubmit = useCallback(function createTimerOnSubmit(tx: SignedTx) {
    if (tx?.txHash) {
      newTimer(createSubmitTimerName(tx.txHash));
    }
  }, []);

  const handleUnlock = useHandleUnlockForSigning();
  const { signAndSubmitStandalone, isSignAndSubmitStandaloneLoading } = useSignAndSubmitStandalone({
    wallet,
    unsignedTx: unsignedTx.transaction,
    signSuccess,
    signError,
    handleUnlock: handleUnlock(wallet.accountId),
    onSubmit,
  });

  const { signAndSubmitLedger, isHardwareWalletSigning, hardwareWalletScreen } =
    useSignAndSubmitLedger({
      unsignedTx: unsignedTx.transaction!,
      onSignSuccess: signSuccess,
      onSignError: signLedgerError,
      flow: Flow.Send,
    });

  const sponsoredInfo = useGetSponsoredSendInfo(wallet);

  const { signAndRelayStandalone, isSignAndRelayLoading } = useSendSignAndRelayStandalone({
    wallet,
    unsignedTx: unsignedTx.transaction,
    signSuccess,
    signError,
    handleUnlock: handleUnlock(wallet.accountId),
    erc20Address: sponsoredInfo?.fiatTokenAddress,
    domainSeparator: sponsoredInfo?.domainSeparator,
    source: 'extension',
  });

  const isLoading =
    ((isSignAndSubmitStandaloneLoading || isSignAndRelayLoading) ?? isHardwareWalletSigning) ||
    isRecalculatingFees;

  useSendConfirmationViewed({
    blockchain: wallet.blockchain.rawValue,
    collectibleChainId,
    sendType,
    chainId: wallet.network.asChain()?.chainId,
    chainName: wallet.network.asChain()?.displayName,
    currencyCode: wallet.currencyCode.code,
    contractAddress: wallet.contractAddress,
    isSponsoredTx: isSponsoredAndRelayEnabled(),
  });

  const activeWalletGroupId = useActiveWalletGroupId();
  const feeWallet = useTxFeeWallet(activeWalletGroupId, unsignedTx.transaction);

  if (!feeWallet) {
    throw new Error('Something went wrong in ConfirmationStep');
  }

  const is1559Enabled = useMemo(() => {
    return isNetwork1559Enabled(wallet.network);
  }, [wallet.network]);

  const isAdjustableMinerFeeEnabled = useIsAdjustableMinerFeeEnabled();

  // revisit isStandalone when custom walletlink messages enable basic wallet users to adjust gas
  // feature flag points to prod value. isProd hook is necessary until we decouple dev and prod.
  const isAdjustableGasEnabled =
    hasLocallyStoredKey && is1559Enabled && (!isProd() || isAdjustableMinerFeeEnabled);

  const transactionCost = useMemo<TransactionCost>(() => {
    if (!unsignedTx?.transaction) {
      return emptyTransactionCost;
    }

    if (is1559Enabled) {
      const eth1559Tx = unsignedTx.transaction as EthereumUnsigned1559Tx;
      const { feeCurrencyCode, feeCurrencyDecimal, currencyCode, lowerBoundFee, upperBoundFee } =
        eth1559Tx;

      const transferValue = eth1559Tx.transferValue || cryptoAmount.value;

      const totalInFiatRange = currencyFormatter.formatToFiatTotalRange({
        feeCurrencyCode,
        currencyCode,
        contractAddress: wallet.contractAddress,
        network: wallet.network,
        blockchain: wallet.blockchain,
        fee: upperBoundFee,
        lowerBoundFee,
        amount: transferValue,
        isConfirmed: false,
        decimals: wallet.decimals,
        includeFee: true,
        feeDecimals: feeCurrencyDecimal,
      });

      const sendAmountInFiat = currencyFormatter.formatToFiat(
        currencyCode,
        wallet.decimals,
        transferValue,
        false,
        wallet.contractAddress,
        wallet.network,
        wallet.blockchain,
      );

      const feeRangeInFiat = currencyFormatter.formatToFiatFeeRange({
        fromCurrencyCode: feeCurrencyCode,
        decimals: feeCurrencyDecimal,
        upperBoundValue: upperBoundFee,
        isAbbreviated: false,
        lowerBoundValue: lowerBoundFee,
        network: wallet.network,
        blockchain: wallet.blockchain,
      });

      const sendAmountInCrypto = currencyFormatter.formatToCrypto({
        currencyCode,
        decimals: wallet.decimals,
        value: transferValue,
        network: wallet.network,
      });

      const feeRangeInCrypto = currencyFormatter.formatToCryptoRange(
        feeCurrencyCode,
        feeCurrencyDecimal,
        lowerBoundFee,
        upperBoundFee,
      );

      if (feeRangeInFiat && sendAmountInFiat && totalInFiatRange) {
        return {
          amount: sendAmountInFiat,
          network: feeRangeInFiat ?? '',
          total: totalInFiatRange,
          isFiat: true,
        };
      }

      if ((feeRangeInFiat || feeRangeInCrypto) && sendAmountInCrypto) {
        const feeRange = feeRangeInFiat ?? feeRangeInCrypto;
        return {
          amount: sendAmountInCrypto,
          network: feeRange ?? '',
          total: '',
          isFiat: false,
        };
      }

      return emptyTransactionCost;
    }

    const legacyTx = unsignedTx.transaction;
    const { feeCurrencyCode, feeCurrencyDecimal, currencyCode, estimatedFee } = legacyTx;

    const transferValue = legacyTx.transferValue || cryptoAmount.value;

    let totalInFiat: string | undefined;
    let extraFeeInFiat: string | undefined;
    let extraFeeInCrypto: string | undefined;

    switch (blockchainName) {
      case SolanaBlockchain.rawValue: {
        const unsignedSOLTx = unsignedTx.transaction as SolanaUnsignedTransaction;

        [totalInFiat] = currencyFormatter.formatFiatTotal(
          [
            {
              value: transferValue,
              decimals: wallet.decimals,
              currencyCode,
              contractAddress: wallet.contractAddress,
              network: wallet.network,
              blockchain: wallet.blockchain,
            },
            {
              currencyCode: feeCurrencyCode,
              decimals: feeCurrencyDecimal,
              value: estimatedFee,
              network: wallet.network,
              blockchain: wallet.blockchain,
            },
            {
              currencyCode: feeCurrencyCode,
              decimals: feeCurrencyDecimal,
              value: unsignedSOLTx.extraFee ?? 0n,
              contractAddress: undefined,
              network: wallet.network,
              blockchain: wallet.blockchain,
            },
          ],
          false,
        );

        extraFeeInFiat = currencyFormatter.formatToFiat(
          feeCurrencyCode,
          feeCurrencyDecimal,
          unsignedSOLTx.extraFee,
          false,
          undefined,
          wallet.network,
          wallet.blockchain,
        );

        extraFeeInCrypto = currencyFormatter.formatToCrypto({
          currencyCode: feeCurrencyCode,
          decimals: feeCurrencyDecimal,
          value: unsignedSOLTx.extraFee,
          network: wallet.network,
          blockchain: wallet.blockchain,
        });
        break;
      }
      default:
        // non-1559 and non-solana transactions
        totalInFiat = currencyFormatter.formatToFiatTotalRange({
          feeCurrencyCode,
          currencyCode,
          contractAddress: wallet.contractAddress,
          network: wallet.network,
          blockchain: wallet.blockchain,
          fee: estimatedFee,
          lowerBoundFee: undefined,
          amount: transferValue,
          isConfirmed: false,
          decimals: wallet.decimals,
          includeFee: true,
          feeDecimals: feeCurrencyDecimal,
        });
        break;
    }

    const sendAmountInFiat = currencyFormatter.formatToFiat(
      currencyCode,
      wallet.decimals,
      transferValue,
      false,
      wallet.contractAddress,
      wallet.network,
      wallet.blockchain,
    );

    const feeAmountInFiat = currencyFormatter.formatToFiat(
      feeCurrencyCode,
      feeCurrencyDecimal,
      estimatedFee,
      false,
      undefined,
      wallet.network,
      wallet.blockchain,
    );

    const sendAmountInCrypto = currencyFormatter.formatToCrypto({
      currencyCode,
      decimals: wallet.decimals,
      value: transferValue,
      network: wallet.network,
      blockchain: wallet.blockchain,
    });

    const feeAmountInCrypto = currencyFormatter.formatToCrypto({
      currencyCode: feeCurrencyCode,
      decimals: feeCurrencyDecimal,
      value: estimatedFee,
      network: wallet.network,
      blockchain: wallet.blockchain,
    });

    const feeAmount = `${feeAmountInFiat} • ${feeAmountInCrypto}`;

    if (feeAmount && sendAmountInFiat && totalInFiat) {
      return {
        amount: sendAmountInFiat,
        network: feeAmount ?? '',
        total: totalInFiat,
        isFiat: true,
        extraFee: extraFeeInFiat,
      };
    }

    if ((feeAmountInFiat || feeAmountInCrypto) && sendAmountInCrypto) {
      const availableFeeAmount = feeAmountInFiat ?? feeAmountInCrypto;
      return {
        amount: sendAmountInCrypto,
        network: availableFeeAmount ?? '',
        total: '',
        isFiat: false,
        extraFee: extraFeeInCrypto,
      };
    }

    return emptyTransactionCost;
  }, [
    unsignedTx.transaction,
    is1559Enabled,
    cryptoAmount.value,
    blockchainName,
    currencyFormatter,
    wallet,
  ]);

  const {
    gasLimit,
    analyticsId,
    chainId,
    feeCurrencyCode,
    networkFeeInUSD,
    networkFeeInCrypto,
    estimatedFee,
  } = analyticsFeeData as FeeAnalyticsLegacy;
  const { minFeeInUSD, maxFeeInUSD, lowerBoundFee, upperBoundFee, minFeeInCrypto, maxFeeInCrypto } =
    analyticsFeeData as FeeAnalytics1559;
  const {
    extraFeeInUSD,
    extraFeeInCrypto,
    estimatedFee: solanaEstimatedFee,
  } = analyticsFeeData as FeeAnalyticsSolana;
  const transactionDetailsErrors = useTransactionDetailsErrors({
    wallet,
    unsignedTx: unsignedTx?.transaction,
    feeWallet,
    flow: 'send',
    isTxSponsored: isSponsoredTx,
  });

  useEffect(
    function logSpamTokenWarning() {
      if (shouldShowSpamTokenWarning) {
        logSendSpamTokenWarningViewed({
          blockchain: wallet.blockchain.rawValue,
          chainId: Number(chainId),
          chainName: wallet.network.asChain()?.displayName,
          currencyCode: wallet.currencyCode.rawValue,
          contractAddress: wallet.contractAddress,
        });
      }
    },
    [
      chainId,
      shouldShowSpamTokenWarning,
      wallet.blockchain.rawValue,
      wallet.contractAddress,
      wallet.currencyCode.rawValue,
      wallet.network,
    ],
  );

  useOnMount(function sendFeeAnalytics() {
    const commonFields = { gasLimit, analyticsId, chainId, feeCurrencyCode };

    try {
      if (blockchainName === EthereumBlockchain.rawValue) {
        if (is1559Enabled) {
          if (!lowerBoundFee || !upperBoundFee) {
            throw new Error('No valid lower and upper bound fees for send 1559 transaction');
          }

          triggerConfirmationGasFeeViewed1559({
            ...commonFields,
            lowerBoundFee,
            upperBoundFee,
            minFeeInUSD,
            maxFeeInUSD,
            maxFeeInCrypto,
            minFeeInCrypto,
          });
        } else {
          if (!estimatedFee) {
            throw new Error('No valid estimated fee for send transaction');
          }

          triggerConfirmationGasFeeViewedLegacy({
            ...commonFields,
            estimatedFee,
            networkFeeInUSD,
            networkFeeInCrypto,
          });
        }
      } else if (blockchainName === SolanaBlockchain.rawValue) {
        if (!solanaEstimatedFee) {
          throw new Error('No valid estimated fee for solana send transaction');
        }

        triggerConfirmationSolNetworkFeeViewed({
          ...commonFields,
          estimatedFee: solanaEstimatedFee,
          networkFeeInUSD,
          networkFeeInCrypto,
          extraFeeInUSD,
          extraFeeInCrypto,
          hasInsufficientFunds: transactionDetailsErrors?.type === 'getMoreCurrencyError',
        });
      }
    } catch (e) {
      triggerAnalyticsGasFeeNotShown(analyticsFeeData);
    }
  });

  const handleOnSend = useCallback(
    async function handleOnSend() {
      triggerAnalyticsSendClicked({ walletType });

      if (isSponsoredAndRelayEnabled() && hasLocallyStoredKey) {
        return signAndRelayStandalone();
      }

      // make sure to clear the temporary flag that disables gasless relay
      // when the component unmounts. This allows to retry using free sends
      // on a new transfer
      updateIsGaslessRelayDisabled(false);

      if (hasLocallyStoredKey) {
        return signAndSubmitStandalone();
      }

      if (isLedgerAccount) {
        return signAndSubmitLedger();
      }

      goToStep('signOnPhone');
      return null;
    },
    [
      triggerAnalyticsSendClicked,
      walletType,
      isSponsoredAndRelayEnabled,
      updateIsGaslessRelayDisabled,
      hasLocallyStoredKey,
      isLedgerAccount,
      goToStep,
      signAndRelayStandalone,
      signAndSubmitStandalone,
      signAndSubmitLedger,
    ],
  );

  const handleOnCancel = useCallback(() => {
    triggerAnalyticsCancelClicked();
    updateIsGaslessRelayDisabled(false);
    history.goBack();
  }, [history, triggerAnalyticsCancelClicked, updateIsGaslessRelayDisabled]);

  // TODO: While implementing the error handlers, we'd need to follow the same
  // pattern we're doing for trade
  // Ref: src/components/trade/steps/ConfirmationPreviewStep/useTransactionDetailsErrors.ts
  const buttonOptions: ButtonProps[] = useMemo(() => {
    return [
      {
        children: formatMessage(messages.cancelButton),
        variant: 'secondary',
        onPress: handleOnCancel,
        testID: 'send-confirm-cancel-button',
      },
      {
        children: formatMessage(messages.sendButton),
        variant: transactionDetailsErrors?.isDisabled ? 'secondary' : 'primary',
        disabled: isLoading || transactionDetailsErrors?.isDisabled,
        loading: isLoading,
        onPress: handleOnSend,
        testID: 'send-confirm-button',
      },
    ];
  }, [
    formatMessage,
    handleOnCancel,
    handleOnSend,
    isLoading,
    transactionDetailsErrors?.isDisabled,
  ]);

  const openAdjustableGasPreset = useCallback(() => {
    triggerAdjustableGasSendFlowEntryClicked();
    goToStep('adjustGasPreset');
  }, [goToStep]);

  const AdjustGasPresetAction = useMemo(
    () =>
      isAdjustableGasEnabled ? (
        <Pressable
          as="button"
          testID="send-confirmation-adjustable-gas-entry"
          onPress={openAdjustableGasPreset}
          background="transparent"
        >
          <Icon name="gear" size="s" color="foreground" spacingStart={1} />
        </Pressable>
      ) : null,
    [isAdjustableGasEnabled, openAdjustableGasPreset],
  );

  const rowDetails: SendRowDetails = {
    transactionCost,
    wallet,
    AdjustGasPresetAction,
    lastUpdateTime: isRealTimeGasFeeEnabled ? lastUpdateTime : undefined,
    isPageLoading: isRecalculatingFees,
    isTxSponsored: isSponsoredAndRelayEnabled(),
  };

  const refreshTransaction = useCallback(async () => {
    const transaction = unsignedTx.transaction;
    const unsignedTxTransferValue = transaction?.transferValue;
    const transferValue: Amount | EntireBalance = {
      kind: unsignedTxTransferValue === wallet.balance ? 'EntireBalance' : 'Amount',
      value: unsignedTxTransferValue!,
    };

    if (!transaction) return;

    const unsignedTransaction = await generateUnsignedTransaction({
      wallet,
      recipientAddress: transaction?.recipientAddress,
      metadata: transaction?.metadata,
      transactionAmount: transferValue,
      txConfiguration: {
        txType: is1559Enabled ? ('1559' as const) : ('Legacy' as const),
        nonce: undefined,
        dataBuffer: (transaction as EthereumUnsignedTx).data,
        ...lastGasPreset.value,
      },
      isSponsoredTx: isSponsoredAndRelayEnabled(),
    });

    if (!unsignedTransaction.transaction) return;

    onChangeUnsignedTx({ ...unsignedTx, transaction: unsignedTransaction.transaction });
  }, [
    is1559Enabled,
    isSponsoredAndRelayEnabled,
    lastGasPreset.value,
    onChangeUnsignedTx,
    unsignedTx,
    wallet,
  ]);

  const refreshNetworkFeeCallback = useCallback(async () => {
    if (isRealTimeGasFeeEnabled) {
      setIsRecalculatingFees(true);
      refreshTransaction()
        .then(() => triggerSendGasFeeRefreshed())
        .catch((err) => triggerSendGasFeeFailed({ errorMessage: err?.message }))
        .finally(() => {
          setLastUpdateTime(new Date());
          setIsRecalculatingFees(false);
        });
    }
  }, [
    isRealTimeGasFeeEnabled,
    refreshTransaction,
    triggerSendGasFeeFailed,
    triggerSendGasFeeRefreshed,
  ]);

  useIntervalForPromises(refreshNetworkFeeCallback, { interval: 31000 });

  const detailRows = useTransactionDetailRowItems(rowDetails);

  const primaryItemProps = useMemo<TopSectionItemProps>(
    () => ({
      testID: 'primaryItem',
      title: wallet.displayName,
      iconSourceOrName: wallet,
      detail: transactionCost.isFiat ? transactionCost.amount : '',
      subDetail: formatAmount({
        currencyFormatter,
        wallet,
        newAmount: cryptoAmount.value,
        isCrypto: true,
        includeCode: true,
      }),
      isAsset: true,
      network: wallet.network,
    }),
    [cryptoAmount.value, currencyFormatter, transactionCost.amount, transactionCost.isFiat, wallet],
  );

  const destination = useMemo(() => {
    const truncatedAddress = getTruncatedAddress(toAddress.value);
    if (!destinationType.value || destinationType.value === 'address') {
      return truncatedAddress;
    }

    return (
      <VStack>
        <TextHeadline as="p" spacingStart={1} tabIndex={0}>
          {searchQuery.value}
        </TextHeadline>
        <TextBody as="p" color="foregroundMuted" spacingStart={1} tabIndex={0}>
          {truncatedAddress}
        </TextBody>
      </VStack>
    );
  }, [searchQuery.value, toAddress.value, destinationType.value]);

  const secondaryItemProps = useMemo<TopSectionItemProps>(
    () => ({
      testID: 'secondaryItem',
      title: destination,
      iconSourceOrName: 'wallet' as IconName,
      isAsset: false,
      assetIconUrl: wallet.imageURL,
      network: wallet.network,
      destinationType: destinationType.value,
      searchQuery: searchQuery.value,
    }),
    [destination, destinationType, wallet, searchQuery],
  );

  const goBack = useCallback(() => {
    // User should not see signOnPhone screen without clicking on
    // Send button. If user presses back button, user should see
    // Select recipient screen instead.
    lastGasPreset.onChange(undefined);
    if (previousStep === 'signOnPhone') {
      goToStep('selectRecipient');
    } else {
      goBackOneStep();
    }
  }, [lastGasPreset, previousStep, goToStep, goBackOneStep]);

  if (isHardwareWalletSigning) {
    return hardwareWalletScreen;
  }

  return (
    <TxDetails
      headerText={formatMessage(messages.title)}
      topSection={
        <TxConfirmationTopSection
          primaryItem={primaryItemProps}
          secondaryItem={secondaryItemProps}
        />
      }
      detailRowItems={detailRows}
      error={transactionDetailsErrors}
      buttonProps={buttonOptions}
      handleBackButton={goBack}
      height={DEFAULT_VIEWPORT_FULL_HEIGHT}
      showTransactionWarning={!!warning}
      transactionWarningMessage={warning}
    />
  );
}

