    [wallet?.imageURL, wallet.network],
  );

  const formatSearchResult = useCallback(
    (searchResult: DestinationSearchResultType) => {
      const { label, type, suggestion } = searchResult;
      return {
        title: formatDestinationName(label, type),
        description: suggestion
          ? formatMessage(messages.recentlySentToThisAddress, {
              duration: formatDistanceToNow(parseISO(suggestion?.lastSentAt)),
            })
          : '',
        renderMedia: searchResultMedia,
        key: label,
        item: searchResult,
        type,
      };
    },
    [formatMessage, searchResultMedia],
  );

  const getRecentRecipients = useCallback(async () => {
    try {
      const unformattedSearchResults = await searchDestinationWithSuggestionsRequest('', wallet);
      setSuggestedSearchResults(unformattedSearchResults.map(formatSearchResult));
    } catch (e: ErrorOrAny) {
      if (e instanceof HTTPError && isAuthError(e)) {
        return;
      }
      throw e;
    }
  }, [
    wallet,
    searchDestinationWithSuggestionsRequest,
    formatSearchResult,
    setSuggestedSearchResults,
  ]);

  useEffect(
    function reloadRecipients() {
      if (isSuggestionsEnabled && toAddress.value === '') {
        formToAddressOnChange('');
        formSearchQueryOnChange('');

        getRecentRecipients();
      }
    },
    [
      isSuggestionsEnabled,
      getRecentRecipients,
      formSearchQueryOnChange,
      formToAddressOnChange,
      toAddress.value,
    ],
  );

  const validateToAddress = useCallback(
    async (inputAddress: string) => {
      if (!inputAddress) {
        return null;
      }
      const isValid = await isValidAddress(wallet.blockchain, inputAddress, wallet.network);
      setHasError(!isValid);
    },
    [wallet.blockchain, wallet.network],
  );

  useEffect(
    function formatSearchResults() {
      if (!searchResults?.results) {
        return;
      }

      setSuggestedSearchResults(searchResults.results.map(formatSearchResult));

      if (!searchResults?.results.length && invalidAddressError) {
        setHasError(true);
      }
    },
    [formatSearchResult, searchResults, searchResults?.uuid, invalidAddressError],
  );

  // eslint-disable-next-line wallet/exhaustive-deps
  const debouncedValidateToAddress = useCallback(
    _debounce(async (inputAddress) => validateToAddress(inputAddress), 250),
    [validateToAddress],
  );

  // eslint-disable-next-line wallet/exhaustive-deps
  const debouncedSearchDestination = useCallback(_debounce(searchDestination, 250), [
    searchDestination,
  ]);

  const handleAddressScan = useCallback(
    async function handleAddressScan(inputAddress: string) {
      try {
        const addressScanResult = await scanForMaliciousAddress(inputAddress, wallet, 'send');

        if (addressScanResult?.isMalicious) {
          setRecipientIsMalicious();
          logScanAddressMaliciousAddressFound({
            context: 'send',
            chainId: wallet.network.asChain()?.chainId,
          });
        } else {
          setRecipientIsNotMalicious();
        }
      } catch (e) {
        logScanAddressRequestError({
          context: 'send',
          chainId: wallet.network.asChain()?.chainId,
          errorMessage: getErrorMessage(e),
        });
        setRecipientIsNotMalicious();
      }
    },
    [scanForMaliciousAddress, wallet, setRecipientIsMalicious, setRecipientIsNotMalicious],
  );

  // eslint-disable-next-line wallet/exhaustive-deps
  const debouncedAddressScan = useCallback(_debounce(handleAddressScan, 250), [handleAddressScan]);

  const handleAuthRequestCompleted = useCallback(() => {
    getRecentRecipients();
  }, [getRecentRecipients]);

  const resetAllErrors = useCallback(() => {
    // clear the input destination error and set the address as non-malicious so the user may proceed
    setHasError(false);
    clearDestinationError();
    setRecipientIsNotMalicious();
  }, [clearDestinationError, setRecipientIsNotMalicious]);

  const handleAddressInputChange = useCallback(
    (event: React.ChangeEvent<HTMLTextAreaElement>) => {
      setSuggestedSearchResults([]);
      const inputAddress = event.target.value;

      formToAddressOnChange(inputAddress);
      resetAllErrors();

      if (!showENSAndUsernameUI) {
        debouncedValidateToAddress(inputAddress);
      } else {
        debouncedSearchDestination(inputAddress);
      }

      debouncedAddressScan(inputAddress);
    },
    [
      formToAddressOnChange,
      resetAllErrors,
      showENSAndUsernameUI,
      debouncedAddressScan,
      debouncedValidateToAddress,
      debouncedSearchDestination,
    ],
  );

  const generateUnsignedTx = useCallback(
    async ({ is1559Transaction, address }: { is1559Transaction: boolean; address?: string }) => {
      const recipientAddress = address || toAddress.value;
      const metadata = new Map<TxMetadataKey, TxMetadataValue>([[TxMetadataKey_txSource, 'send']]);

      metadata.set(TxMetadataKey_analyticsId, uuidv4());
      metadata.set(TxMetadataKey_hasRecordedConfirmEvent, false);

      if (!transferValue.value) {
        throw new Error('SelectRecipient generateUnsignedTx failed due to missing TransferValue.');
      }

      const txConfig = {
        txType: is1559Transaction ? ('1559' as const) : ('Legacy' as const),
      };

      const result = await generateUnsignedTransaction({
        wallet,
        transactionAmount: transferValue.value,
        recipientAddress,
        metadata,
        txConfiguration: txConfig,
        isSponsoredTx,
        isUTXOScriptFromTransactionEnabled,
        isSolanaPriorityFeeEnabled,
      });

      const ethUnsignedTx = result.transaction as EthereumUnsignedTx;

      if (!ethUnsignedTx) {
        throw new Error('Generating unsigned 1559 tx failed.');
      }

      if (ethUnsignedTx.gasLimit) {
        initialGasLimit.onChange(ethUnsignedTx.gasLimit);
      }

      formUnsignedTxResultOnChange(result);
      cryptoAmount.onChange(ethUnsignedTx.transferValue);
      goToStep('confirmation');
    },
    [
      toAddress.value,
      transferValue.value,
      wallet,
      isSponsoredTx,
      isUTXOScriptFromTransactionEnabled,
      isSolanaPriorityFeeEnabled,
      formUnsignedTxResultOnChange,
      cryptoAmount,
      goToStep,
      initialGasLimit,
    ],
  );

  const generateNFTUnsignedTx = useCallback(
    async (response: CollectibleSendTxResponse) => {
      if (!response.txParamList || response.txParamList.length === 0) {
        const errorMessage =
          'SelectRecipient generateUnsignedTx failed due to missing TransferValue.';
        logGenerateNFTUnsignedSendTxFailed({
          blockchain: wallet.blockchain.rawValue,
          chainId: wallet.network.asChain()?.chainId,
          chainName: wallet.network.asChain()?.displayName,
          currencyCode: wallet.currencyCode.code,
          contractAddress: wallet.contractAddress,
          errorMessage,
        });
        throw new Error(errorMessage);
      }

      const params = response.txParamList[0];

      const metadata = new Map<TxMetadataKey, TxMetadataValue>([
        [TxMetadataKey_sendNFTId, params.sendNFTId],
        [TxMetadataKey_txSource, 'nft-send'],
        [TxMetadataKey_hasRecordedConfirmEvent, false],
      ]);

      const zeroAmount = { kind: 'Amount', value: 0n } as Amount;

      const result = await generateUnsignedTransaction({
        wallet,
        transactionAmount: zeroAmount,
        recipientAddress: params.toAddress,
        metadata,
        txConfiguration: {
          txType: isNetwork1559Enabled(wallet.network) ? '1559' : 'Legacy',
          selectedBaseFeePerGas: BigInt(params.gasBaseFee),
          selectedMaxFeePerGas: BigInt(params.gasPrice),
          selectedMaxPriorityFeePerGas: BigInt(params.gasPriorityFee),
          selectedGasLimit: BigInt(params.gasLimit),
          dataBuffer: Buffer.from(params.data, 'base64'),
        },
      });

      const ethUnsignedTx = result.transaction as EthereumUnsigned1559Tx;

      if (!ethUnsignedTx?.gasLimit) {
        const errorMessage = 'Generating unsigned 1559 tx failed.';
        logGenerateNFTUnsignedSendTxFailed({
          blockchain: wallet.blockchain.rawValue,
          chainId: wallet.network.asChain()?.chainId,
          chainName: wallet.network.asChain()?.displayName,
          currencyCode: wallet.currencyCode.code,
          contractAddress: wallet.contractAddress,
          errorMessage,
        });
        throw new Error(errorMessage);
      }

      logGenerateNFTUnsignedSendTxSuccess({
        blockchain: wallet.blockchain.rawValue,
        collectibleChainId: collectible.value?.chainId,
        chainId: wallet.network.asChain()?.chainId,
        chainName: wallet.network.asChain()?.displayName,
        currencyCode: wallet.currencyCode.code,
        contractAddress: wallet.contractAddress,
      });
      formUnsignedTxResultOnChange(result);
      initialGasLimit.onChange(ethUnsignedTx.gasLimit);
      cryptoAmount.onChange(ethUnsignedTx.transferValue);
      goToStep('confirmation');
    },
    [cryptoAmount, formUnsignedTxResultOnChange, goToStep, initialGasLimit, wallet, collectible],
  );

  const logNFTSendTxDataFetchError = useCallback(
    (error: ErrorOrAny) => {
      const analyticsData = {
        blockchain: wallet.blockchain.rawValue,
        collectibleChainId: collectible.value?.chainId,
        chainId: wallet.network.asChain()?.chainId,
        chainName: wallet.network.asChain()?.displayName,
        currencyCode: wallet.currencyCode.code,
        contractAddress: wallet.contractAddress,
        errorMessage: error?.message,
      };

      if (!(error instanceof HTTPError)) {
        logFetchNFTSendTxDataGenericError(analyticsData);
        return;
      }

      if (error.status === 400) {
        if (error.message === CONTRACT_EXECUTION) {
          logFetchNFTSendTxDataContractError(analyticsData);
          return;
        }

        logFetchNFTSendTxDataBadRequestError(analyticsData);
        return;
      }

      logFetchNFTSendTxDataGenericError(analyticsData);
    },
    [wallet, collectible],
  );

  const getCollectibleSendTxDataResponse = useCallback(
    async (address?: string) => {
      if (collectible?.value) {
        getCollectibleSendTxData(
          collectible.value.contractAddress,
          collectible.value.tokenId,
          address ?? toAddress.value,
          wallet.primaryAddress,
          collectible.value.tokenType,
          collectible.value.chainId,
          collectibleAmount.value > 1n ? collectibleAmount.value.toString() : undefined,
        )
          .then((response: CollectibleSendTxResponse) => {
            logFetchNFTSendTxDataSuccess({
              blockchain: wallet.blockchain.rawValue,
              chainId: wallet.network.asChain()?.chainId,
              chainName: wallet.network.asChain()?.displayName,
              currencyCode: wallet.currencyCode.code,
              contractAddress: wallet.contractAddress,
              collectibleChainId: collectible.value?.chainId,
            });
            generateNFTUnsignedTx(response);
          })
          .catch((error) => {
            logNFTSendTxDataFetchError(error);

            if (error instanceof HTTPError) {
              if (error.message === INVALID_DESTINATION) {
                setHasError(true);
                return;
              }
              setSendTxErrorMessage(error.message);
            } else {
              throw new Error('SelectRecipient generateNFTUnsignedTx failed.');
            }
          });
      }
    },
    [
      generateNFTUnsignedTx,
      wallet,
      collectible,
      collectibleAmount,
      toAddress,

      logNFTSendTxDataFetchError,
    ],
  );

  const handleOnNext = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (_: any, address?: string, searchQueryString?: string) => {
      triggerAnalyticsSelectRecipientNextClicked();
      const destinationSearchQuery = searchQueryString ?? toAddress.value;
      formSearchQueryOnChange(destinationSearchQuery);

      const is1559Transaction = isNetwork1559Enabled(wallet.network);
      if (collectible?.value) {
        getCollectibleSendTxDataResponse(address);
      } else {
        generateUnsignedTx({ is1559Transaction, address });
      }
    },
    [
      triggerAnalyticsSelectRecipientNextClicked,
      toAddress.value,
      formSearchQueryOnChange,
      wallet.network,
      collectible?.value,
      getCollectibleSendTxDataResponse,
      generateUnsignedTx,
    ],
  );

  const handleSuggestedDestination = useCallback(
    (destination: string) => {
      async function resolveDestinationReq() {
        const result = await safeResolveDestination(destination, wallet);
        if (!result?.address) return; // TODO figure out the error state for this case

        formToAddressOnChange(result.address);
        // we need to pass in result.address because otherwise handleOnNext will refer
        // to the stale value for toAddress in the form
        handleOnNext(undefined, result.address, destination);
      }
      resolveDestinationReq();
    },
    [wallet, formToAddressOnChange, handleOnNext],
  );

  const handleSuggestionItemClick = useCallback(
    (searchResult: DestinationSearchResultType) => {
      formDestinationTypeOnChange(searchResult.type);
      return handleSuggestedDestination(searchResult.label);
    },
    [formDestinationTypeOnChange, handleSuggestedDestination],
  );

  const goBack = useCallback(() => {
    if (collectible?.value) {
      history.goBack();
    } else {
      goBackOneStep();
    }
  }, [goBackOneStep, collectible, history]);

  const suggestionListTitle = useMemo(
    () =>
      !toAddress.value && isSuggestionsEnabled && suggestedSearchResults.length !== 0
        ? formatMessage(messages.suggestedAddressLabel)
        : null,
    [formatMessage, isSuggestionsEnabled, suggestedSearchResults.length, toAddress.value],
  );

  const handleDismissErrorClick = useCallback(() => {
    resetAllErrors();
  }, [resetAllErrors]);

  const handleClearAddressClick = useCallback(() => {
    if (recipientInputRef.current) {
      // clear the input field
      recipientInputRef.current.value = '';
      // reset the height of the textarea
      recipientInputRef.current.style.height = '';
    }

    handleAddressInputChange({ target: { value: '' } } as React.ChangeEvent<HTMLTextAreaElement>);
  }, [handleAddressInputChange]);

  const emptyStateContent = useMemo(() => {
    const destinationError = isRecipientMalicious
      ? DestinationError.maliciousAddress
      : destinationErrorType;

    return destinationError || (hasNewRecipientTabEnabled && !searchResults?.results.length) ? (
      <NoRecipientSuggestions
        errorType={destinationError}
        wallet={wallet}
        handleSuggestionClick={handleSuggestionItemClick}
        handleDismissErrorClick={handleDismissErrorClick}
        handleClearAddressClick={handleClearAddressClick}
      />
    ) : null;
  }, [
    isRecipientMalicious,
    destinationErrorType,
    hasNewRecipientTabEnabled,
    searchResults?.results.length,
    wallet,
    handleSuggestionItemClick,
    handleDismissErrorClick,
    handleClearAddressClick,
  ]);

  const helpCenterLink = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (text: any) => (
      <Link variant="body" to={HELP_CENTER_URL} openInNewWindow>
        {text}
      </Link>
    ),
    [],
  );

  const { errorMessage, errorDetails, primaryButtonText, secondaryButtonText } =
    useSendCollectibleErrorData({
      sendTxErrorMessage,
      collectible: collectible?.value,
      helpCenterLink,
    });

  if (collectible.value && sendTxErrorMessage !== undefined) {
    return (
      <SelectRecipientStepErrorMessage
        sendTxErrorMessage={sendTxErrorMessage}
        errorMessage={errorMessage}
        errorDetails={errorDetails}
        collectible={collectible.value}
        primaryButtonText={primaryButtonText}
        secondaryButtonText={secondaryButtonText}
      />
    );
  }

  return (
    <Screen
      header={
        <NavBar variant="secondary" title={formatMessage(messages.title)} handleBack={goBack} />
      }
    >
      <VStack gap={2} alignContent="center" minHeight="370">
        <SendAddressInput
          key="send-address-input"
          blockchain={wallet.displayName}
          hasError={hasError}
          handleInput={handleAddressInputChange}
          invalidAddressType={invalidAddressError}
          maxLength={wallet.blockchain.addressCharLength}
          ref={recipientInputRef}
        />
        {showENSAndUsernameUI ? (
          <SearchSuggestionsList<DestinationSearchResultType>
            suggestions={suggestedSearchResults}
            isSuggestionsEnabled={isSuggestionsEnabled}
            title={suggestionListTitle}
            handleDestinationRowClick={handleSuggestionItemClick}
            searchQuery={toAddress.value}
            emptyStateContent={emptyStateContent}
            upsellComponent={
              <UpsellAuthorization
                onComplete={handleAuthRequestCompleted}
                upsellMessage={formatMessage(messages.authenticationRequestUpsell)}
              />
            }
          />
        ) : null}
      </VStack>
    </Screen>
  );
}

import { useCallback, useMemo } from 'react';
import { useIntl } from 'react-intl';
import { styled } from '@linaria/react';
import { triggerCustomTokenAdded } from 'cb-wallet-analytics/settings';
import { CurrencyCode } from 'cb-wallet-data/models/CurrencyCode';
import { useCustomNetworkArgs } from 'cb-wallet-data/stores/CustomNetworks/hooks/useCustomNetworkArgs';
import { Network } from 'cb-wallet-data/stores/Networks/models/Network';
import { useActiveWalletGroupId } from 'cb-wallet-data/stores/WalletGroups/hooks/useActiveWalletGroupId';
import { useAddCustomEthToken } from 'cb-wallet-data/stores/Wallets/hooks/useAddCustomEthToken';
import { Form, Formik, FormikHelpers } from 'formik';
import { Button, ButtonGroup } from '@cbhq/cds-web/buttons';
import { VStack } from '@cbhq/cds-web/layout';
import { TextLabel2 } from '@cbhq/cds-web/typography';

import { createValidationSchema, initialValues, messages, Token } from './AddCustomToken.form';
import { TextInput } from './ConnectedTextInput';

const FULL_HEIGHT = {
  height: '100%',
};

type Props = {
  network?: Network;
};

export function AddCustomToken({ network }: Props) {
  const { formatMessage } = useIntl();
  const customNetworks = useCustomNetworkArgs();
  const activeWalletGroupId = useActiveWalletGroupId();
  const addCustomEthToken = useAddCustomEthToken(activeWalletGroupId);
  const customNetwork = useMemo(
    () => customNetworks.find(({ network: n }) => network && Network.isEqual(network, n)),
    [network, customNetworks],
  );

  const validationSchema = useMemo(() => createValidationSchema(formatMessage), [formatMessage]);

  const handleSubmit = useCallback(
    async (values: Token, { setStatus, setSubmitting }: FormikHelpers<Token>) => {
      if (!customNetwork) return null;

      try {
        const currencyCode = new CurrencyCode(values.symbol);
        await addCustomEthToken(
          currencyCode,
          values.contractAddress,
          customNetwork,
          BigInt(values.decimal),
        );

        triggerCustomTokenAdded({
          contractAddress: values.contractAddress,
          tokenSymbol: currencyCode.rawValue,
          chainId: Number(customNetwork.network.asChain()?.chainId),
          chainName: customNetwork.name,
          fromWatchAsset: false,
        });

        setStatus('');
        setSubmitting(false);
        window.close();
      } catch (error: ErrorOrAny) {
        setStatus(error.message);
        setSubmitting(false);
      }
    },
    [addCustomEthToken, customNetwork],
  );

  const values = useMemo(
    () => ({
      ...initialValues,
      ...(customNetwork?.network.rawValue && { networkRawValue: customNetwork.network.rawValue }),
    }),
    [customNetwork?.network],
  );

  return (
    <VStack height="100%" spacing={1}>
      <Formik initialValues={values} validationSchema={validationSchema} onSubmit={handleSubmit}>
        {({ status, isSubmitting, isValid, dirty }) => (
          <Form style={FULL_HEIGHT}>
            <Grid>
              <div>
                <TextInput
                  testID="custom-token-contract-address-input"
                  label={formatMessage(messages.contractAddress)}
                  name="contractAddress"
                />
                <TextInput
                  testID="custom-token-symbol-input"
                  label={formatMessage(messages.symbol)}
                  name="symbol"
                />
                <TextInput
                  testID="custom-token-decimal-input"
                  label={formatMessage(messages.decimal)}
                  name="decimal"
                />

                {!!status && (
                  <TextLabel2 testID="text-input-error-label" as="span" color="negative">
                    {status}
                  </TextLabel2>
                )}
              </div>

              <ButtonGroup block accessibilityLabel={formatMessage(messages.buttonGroup)}>
                <Button
                  testID="custom-token-save"
                  type="submit"
                  variant="primary"
                  loading={isSubmitting}
                  disabled={!isValid || !dirty}
                >
                  {formatMessage(messages.save)}
                </Button>
              </ButtonGroup>
            </Grid>
          </Form>
        )}
      </Formik>
    </VStack>
  );
}

const Grid = styled.div`
  display: grid;
  grid-template-rows: 1fr auto;
  height: 100%;
`;

import { useCallback, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { useHistory } from 'react-router-dom';
import { logEvent } from 'cb-wallet-analytics/utils/log';
import { NavBar } from 'wallet-cds-extension/components/Header/NavBar';
import { Screen } from 'wallet-cds-extension/components/Screen/Screen';
import { ValidatedTextInput } from 'wallet-cds-extension/components/ValidatedTextInput/ValidatedTextInput';
import { Button } from '@cbhq/cds-web/buttons';
import { Spacer, VStack } from '@cbhq/cds-web/layout';
import { TextBody } from '@cbhq/cds-web/typography/TextBody';
import { ActionType, ComponentType } from '@cbhq/client-analytics';

import { appLockRepository } from ':extension/init/repositories';

const AUTOLOCK_MIN_MINS = 5;
const AUTOLOCK_MAX_MINS = 4320;
const MS_IN_MINS = 60000;

const messages = defineMessages({
  title: {
    description: 'Title for Security lock Page',
    defaultMessage: 'Security lock',
  },
  inputLabel: {
    description: 'Label for Auto Lock Timer Input',
    defaultMessage: 'Lock after',
  },
  minutes: {
    description: 'Minutes suffix for auto-lock timer input',
    defaultMessage: 'minutes',
  },
  instructions: {
    description: 'Instructions for auto-lock timer',
    defaultMessage:
      'This timer will determine how long to wait before automatically locking your wallet after being idle.',
  },
  saveBtnLabel: {
    description: 'Label for button to save time input value',
    defaultMessage: 'Save',
  },
  invalidTimeValueError: {
    description: 'Error message for invalid time value',
    defaultMessage: 'Enter a value between 5 and 4320 (3 days).',
  },
});

export function AutoLockTimer() {
  const autoLockTimeoutMs =
    appLockRepository.autoLockTimeout ?? appLockRepository.DEFAULT_TIMEOUT_MS;
  const autoLockTimeoutMins = autoLockTimeoutMs / (60 * 1000);
  const autoLockTimeout = autoLockTimeoutMins ? autoLockTimeoutMins.toString() : '';
  const [inputTime, setInputTime] = useState<string>(autoLockTimeout);
  const [inputError, setInputError] = useState<boolean>(false);
  const { formatMessage } = useIntl();
  const history = useHistory();

  const handleInput = useCallback(
    (input: string) => {
      if (inputError) setInputError(!inputError);
      const stripped = input.replace(/[^0-9]/g, ''); // disallow non-numeric input
      setInputTime(stripped);
    },
    [inputError],
  );

  const handleSave = useCallback(() => {
    logEvent('auto_lock_timer.save_timer_btn', {
      loggingId: '5c4ec97a-ae37-4ce2-9bbe-445dd60daea0',
      timeoutMin: inputTime,
      action: ActionType.click,
      componentType: ComponentType.button,
    });
    const timeoutMins = parseInt(inputTime, 10);
    if (timeoutMins < AUTOLOCK_MIN_MINS || timeoutMins > AUTOLOCK_MAX_MINS || isNaN(timeoutMins)) {
      setInputError(true);
      return;
    }
    const timeoutMinsInMs = timeoutMins * MS_IN_MINS;

    appLockRepository.setAutoLockTimeout(timeoutMinsInMs);
    history.goBack();
  }, [inputTime, history]);

  return (
    <Screen
      height="100%"
      header={
        <NavBar
          variant="secondary"
          title={formatMessage(messages.title)}
          handleBack={history.goBack}
        />
      }
    >
      <VStack height="100%" justifyContent="space-between" spacing={3}>
        <VStack>
          <ValidatedTextInput
            autoFocus
            name="autoLockTime"
            label={formatMessage(messages.inputLabel)}
            value={inputTime}
            givenError={inputError ? formatMessage(messages.invalidTimeValueError) : undefined}
            onChange={handleInput}
            maxLength={4}
            suffix={formatMessage(messages.minutes)}
            testID="timeoutInput"
          />
          <Spacer vertical={1} />
          <TextBody as="p" color="foregroundMuted" spacingEnd={1}>
            {formatMessage(messages.instructions)}
          </TextBody>
        </VStack>
        <Button
          disabled={!inputTime || inputError}
          onPress={handleSave}
          block
          variant="primary"
          testID="auto-lock-save-btn"
        >
          {formatMessage(messages.saveBtnLabel)}
        </Button>
      </VStack>
    </Screen>
  );
}

import { useCallback, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
