  changePasswordButtonText: {
    defaultMessage: 'Change password',
    description: 'Button text for confirming a password change',
  },
  incorrectPassword: {
    defaultMessage: 'Incorrect password',
    description: 'Text input error state when an incorrect password is entered',
  },
  instructionText: {
    defaultMessage:
      "Change the password to unlock your wallet each time you use your computer. It can't be used to recover your wallet.",

    description: 'Instruction text for the change password screen',
  },
  oldPasswordLabel: {
    defaultMessage: 'Old password',
    description: 'Label for old password input',
  },
  oldPasswordPlaceholder: {
    defaultMessage: 'Enter old password',
    description: 'Placeholder text for old password input',
  },
});

export function ChangePassword() {
  const { formatMessage } = useIntl();
  const history = useHistory();
  const [oldPassword, setOldPassword] = useState<string>('');
  const [newPassword, setNewPassword] = useState<string>('');
  const [passwordsMatch, setPasswordsMatch] = useState<boolean>(false);
  const [passwordValid, setPasswordValid] = useState<boolean>(false);
  const [passwordIncorrectMessage, setPasswordIncorrectMessage] = useState<string>('');
  const toast = useToast();

  const changePassword = useCallback(async () => {
    logEvent('change_password.submit', {
      loggingId: '78e3c1a1-9986-4e53-aacc-1d37e9151146',
      action: ActionType.click,
      componentType: ComponentType.button,
    });

    try {
      await appLockRepository.changePassword(oldPassword, newPassword);
      logEvent('change_password.success', {
        loggingId: '1697c970-1774-45c0-8bd6-89a69eafff6d',
        action: ActionType.render,
        componentType: ComponentType.unknown,
      });
      history.push('/settings');
      toast.show('Password changed');
    } catch (err) {
      logEvent('change_password.fail', {
        loggingId: '4332645a-05cc-462a-89e2-6fb6e68b1a76',
        action: ActionType.render,
        componentType: ComponentType.banner,
      });
      setPasswordIncorrectMessage(formatMessage(messages.incorrectPassword));
    }
  }, [formatMessage, history, newPassword, oldPassword, toast]);

  const onChangePassword = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (value: any, isMatch: any, isValid: any) => {
      setNewPassword(value);
      setPasswordsMatch(isMatch);
      setPasswordValid(isValid);
    },
    [setNewPassword, setPasswordsMatch, setPasswordValid],
  );

  const handleOnChangeOldPassword = useCallback(
    (value: string) => {
      setOldPassword(value);
      // Reset the error message when the user starts typing again
      setPasswordIncorrectMessage('');
    },
    [setOldPassword, setPasswordIncorrectMessage],
  );

  return (
    <Screen
      header={
        <NavBar
          variant="secondary"
          title={formatMessage(messages.title)}
          handleBack={history.goBack}
        />
      }
    >
      <VStack spacingBottom={3} spacingHorizontal={2}>
        <TextBody testID="change-password-instruction-text" as="div" color="foregroundMuted">
          {formatMessage(messages.instructionText)}
        </TextBody>
        <VStack spacingTop={3} spacingBottom={1} justifyContent="flex-start">
          <ValidatedTextInput
            testID="change-password-old-password-input"
            autoFocus
            type="password"
            name="oldPassword"
            givenError={passwordIncorrectMessage}
            placeholder={formatMessage(messages.oldPasswordPlaceholder)}
            label={formatMessage(messages.oldPasswordLabel)}
            value={oldPassword}
            onChange={handleOnChangeOldPassword}
          />
          <SetPassword resetMode onChange={onChangePassword} gap={1} />
        </VStack>
        <Box spacingHorizontal={1}>
          <Button
            block
            testID="change-password-button"
            disabled={!passwordsMatch || !passwordValid || !oldPassword}
            onPress={changePassword}
          >
            {formatMessage(messages.changePasswordButtonText)}
          </Button>
        </Box>
      </VStack>
    </Screen>
  );
}

import { useMemo, useRef } from 'react';
import { css } from '@linaria/core';
import { styled } from '@linaria/react';
import { triggerInputErrors } from 'cb-wallet-analytics/settings';
import { useField } from 'formik';
import { Spacer, VStack } from '@cbhq/cds-web/layout';
import { TextLabel2 } from '@cbhq/cds-web/typography/TextLabel2';

type ConnectedTextInputProps = {
  autoFocus?: boolean;
  defaultSubscript?: string;
  disabled?: boolean;
  givenError?: string;
  label?: string;
  name: string;
  placeholder?: string;
  successMessage?: string;
  testID?: string;
  type?: string;
};

export function TextInput({
  autoFocus = false,
  defaultSubscript = '',
  disabled = false,
  successMessage = '',
  label,
  name,
  placeholder,
  testID,
  type = 'text',
}: ConnectedTextInputProps) {
  const inputContainer = useRef<HTMLDivElement | null>(null);
  const input = useRef<HTMLInputElement | null>(null);

  const [field, meta] = useField(name);

  const subScript = useMemo(() => {
    if (meta.touched && meta.error) {
      triggerInputErrors({
        error: meta.error,
        label,
      });

      return (
        <>
          <TextLabel2 testID="text-input-error-label" as="span" color="negative">
            {meta.error}
          </TextLabel2>
          <Spacer vertical={4} />
        </>
      );
    }

    const subscriptMessage = meta.value?.length !== 0 ? successMessage : defaultSubscript;
    return (
      <>
        <TextLabel2 as="span" color="foregroundMuted">
          {subscriptMessage}
        </TextLabel2>
      </>
    );
  }, [defaultSubscript, label, meta.error, meta.touched, meta.value?.length, successMessage]);

  return (
    <VStack alignItems="flex-start" width="100%">
      <div className={inputWrapper}>
        {label && (
          <label className={labelStyles} htmlFor={name}>
            {label}
          </label>
        )}
        <InputContainer key="connected-text-input-container" ref={inputContainer}>
          <StyledInput
            autoFocus={autoFocus}
            ref={input}
            disabled={disabled}
            minLength={1}
            type={type}
            placeholder={placeholder ?? ''}
            aria-label={label ?? placeholder ?? ''}
            data-testid={testID}
            {...field}
          />
        </InputContainer>
      </div>
      <SubScriptWrapper>{subScript}</SubScriptWrapper>
    </VStack>
  );
}

