enum Option {
  changeNetwork = 'changeNetwork',
  disconnect = 'disconnect',
}

type MoreOptions = {
  title: string;
  value: Option;
  onPress: () => void;
  testID: string;
  show: boolean;
};

type DappConnectionInfoRowComponentProps = {
  dapp: Dapp;
  onDappSelect?: (dapp: Dapp) => void;
};

function DappConnectionInfoRowComponent({
  dapp,
  onDappSelect,
}: DappConnectionInfoRowComponentProps) {
  const { dappURL, dappName, providerType } = dapp;
  const hostname = getHostNameForDapp(dappURL, true);

  const isEthProvider = useMemo(() => providerType === 'window.ethereum', [providerType]);

  const disconnect = useObservableCallback(
    (subscription) => {
      subscription?.unsubscribe();
      triggerDisconnectClicked({ dappName: dapp.dappName });

      return dappConnectionRepository.removeConnection(dapp).subscribe();
    },
    [dapp],
  );

  const changeNetwork = useCallback(() => {
    onDappSelect?.(dapp);
    triggerChangeDappNetwork({
      dappName: dapp.dappName,
      dappUrl: dapp.dappURL,
    });
  }, [dapp, onDappSelect]);

  const dropdownContent = useMemo(() => {
    const moreOptions: MoreOptions[] = [
      {
        title: 'Change network',
        value: Option.changeNetwork,
        onPress: changeNetwork,
        testID: `dapp-connection-change-network-${hostname}`,
        show: isEthProvider,
      },
      {
        title: 'Disconnect',
        value: Option.disconnect,
        onPress: disconnect,
        testID: `dapp-connection-disconnect-${hostname}`,
        show: true,
      },
    ];
    return (
      <>
        {moreOptions.map(
          ({ title, value, onPress, testID, show }) =>
            show && (
              <SelectOption
                value={value}
                title={
                  <TextBody as="p" color="foregroundMuted">
                    {title}
                  </TextBody>
                }
                key={[dappURL, value].join(';')}
                compact
                onPress={onPress}
                testID={testID}
              />
            ),
        )}
      </>
    );
  }, [changeNetwork, dappURL, disconnect, hostname, isEthProvider]);

  const createAssetLikeProps = useCallback((): AssetLikeProps => {
    const { dappLogoURL, dappLogoURLAlt, overriddenChainId } = dapp;
    const ethereumChain = overriddenChainId
      ? EthereumNetworkMap.fromChainId(BigInt(overriddenChainId))
      : null;
    const solanaChain = SolanaNetworkMap.whitelisted.SOLANA_MAINNET;

    return {
      iconUrl: dappLogoURL || dappLogoURLAlt,
      network: ethereumChain ? asNetwork(ethereumChain) : asSolanaNetwork(solanaChain),
      showNetworkIconOverride: true,
    };
  }, [dapp]);

  const openDAppLink = useCallback(() => {
    chrome.tabs.create({
      active: false,
      url: dappURL,
    });
  }, [dappURL]);

  return (
    <SmallListCell data-testid="dapp-connection-row" key={dappURL}>
      <ListCell
        media={
          <AssetIcon
            testID="dapp-connection-asset-icon"
            asset={createAssetLikeProps()}
            shape="squircle"
          />
        }
        description={
          <>
            <TextLabel2 testID="dapp-connection-name" as="p" className="overrideTitle">
              {dappName}
            </TextLabel2>
            <Link
              testID="dapp-connection-host-name"
              color="foregroundMuted"
              onPress={openDAppLink}
              title={hostname}
            >
              {hostname}
            </Link>
          </>
        }
        detail={
          <Dropdown content={dropdownContent}>
            <CustomAccessoryContainer>
              <IconButton
                transparent
                name="more"
                testID={`dapp-connection-more-options-${hostname}`}
              />
            </CustomAccessoryContainer>
          </Dropdown>
        }
        priority="end"
      />
    </SmallListCell>
  );
}

