  }, [push]);

  const handleGoToPrivateKeyExport = useCallback(() => {
    const url = generatePath(RoutesEnum.SHOW_PRIVATE_KEY, {
      accountId: walletGroup.accountId,
      walletIndex: walletGroup.walletIndex.toString(),
    });
    return push(url);
  }, [push, walletGroup.accountId, walletGroup.walletIndex]);

  const handleGoToThemeColor = useCallback(() => {
    const url = generatePath(RoutesEnum.THEME_COLOR, {
      walletGroupId: walletGroup.id,
    });
    return push(url);
  }, [push, walletGroup.id]);

  const isPrevRouteSettings = useMemo(() => {
    return (
      // @ts-expect-error Type def for history is missing entries
      history.entries.length > 2 && history.entries.at(-2).pathname === RoutesEnum.SETTINGS
    );
  }, [history]);

  const undoHideWallet = useCallback(async () => {
    try {
      await setWalletGroupIsHidden(walletGroup.id, walletGroup.isHidden);
    } catch {
      toast.show(sharedMessages.hideWalletError, { bottomOffset: 50 });
    }
  }, [
    setWalletGroupIsHidden,
    sharedMessages.hideWalletError,
    toast,
    walletGroup.id,
    walletGroup.isHidden,
  ]);

  const undoUnhideWallet = useCallback(async () => {
    try {
      await setWalletGroupIsHidden(walletGroup.id, walletGroup.isHidden);
    } catch {
      toast.show(sharedMessages.hideWalletError, { bottomOffset: 50 });
    }
  }, [
    setWalletGroupIsHidden,
    sharedMessages.hideWalletError,
    toast,
    walletGroup.id,
    walletGroup.isHidden,
  ]);

  const undoHideActiveWallet = useCallback(async () => {
    try {
      await setWalletGroupIsHidden(walletGroup.id, walletGroup.isHidden);
      setActiveWalletGroupId(walletGroup.id);
    } catch {
      toast.show(sharedMessages.hideWalletError, { bottomOffset: 50 });
    }
  }, [
    setActiveWalletGroupId,
    setWalletGroupIsHidden,
    sharedMessages.hideWalletError,
    toast,
    walletGroup.id,
    walletGroup.isHidden,
  ]);

  const handleHiddenSwitch = useCallback(async () => {
    try {
      const newIsHiddenStatus = !walletGroup.isHidden;
      await setWalletGroupIsHidden(walletGroup.id, newIsHiddenStatus);
      triggerWalletGroupVisibilityToggled({
        action: ActionType.click,
        componentType: ComponentType.checkbox,
        walletIndex: walletGroup.walletIndex.toString(),
        isHidden: newIsHiddenStatus,
      });

      if (activeWalletGroupId === walletGroup.id) {
        setActiveWalletGroupId(availableWalletGroups[0]?.id);
        // <displayName> is hidden. Switched to <newWalletGroupDisplayName>.
        toast.show(
          `${displayName} ${sharedMessages.activeWalletHiddenToastText} ${getWalletGroupDisplayName(
            newWalletGroupToDisplay,
          )}.`,
          {
            action: {
              label: 'Undo',
              onPress: undoHideActiveWallet,
            },
            bottomOffset: 50,
          },
        );

        if (isPrevRouteSettings) {
          push(RoutesEnum.PORTFOLIO);
        } else {
          history.goBack();
        }
      } else if (!walletGroup.isHidden) {
        // <walletGroupDisplayName> is hidden
        toast.show(`${displayName} ${sharedMessages.walletHiddenToastText}`, {
          action: {
            label: 'Undo',
            onPress: undoHideWallet,
          },
          bottomOffset: 50,
        });
        history.goBack();
      } else {
        // <walletGroupDisplayName> is visible
        toast.show(`${displayName} ${sharedMessages.walletVisibleToastText}`, {
          bottomOffset: 50,
          action: {
            label: 'Undo',
            onPress: undoUnhideWallet,
          },
        });
        history.go(-2);
      }
    } catch {
      toast.show(sharedMessages.hideWalletError, { bottomOffset: 50 });
    }
  }, [
    setWalletGroupIsHidden,
    walletGroup.id,
    walletGroup.isHidden,
    walletGroup.walletIndex,
    activeWalletGroupId,
    history,
    setActiveWalletGroupId,
    availableWalletGroups,
    toast,
    displayName,
    sharedMessages.activeWalletHiddenToastText,
    sharedMessages.walletHiddenToastText,
    sharedMessages.walletVisibleToastText,
    sharedMessages.hideWalletError,
    getWalletGroupDisplayName,
    newWalletGroupToDisplay,
    undoHideActiveWallet,
    undoHideWallet,
    undoUnhideWallet,
    isPrevRouteSettings,
    push,
  ]);

  const isHideWalletDisabled = useMemo(() => {
    return !walletGroup.isHidden && visibleWalletGroups.length <= 1;
  }, [visibleWalletGroups.length, walletGroup.isHidden]);

  const handleDisabledClick = useCallback(() => {
    toast.show(sharedMessages.disabledClickToastText, { bottomOffset: 50 });
  }, [sharedMessages.disabledClickToastText, toast]);

  return (
    <VStack testID={testID}>
      <VStack alignItems="center">
        <VStack spacingBottom={1} gap={2} alignItems="center">
          <DynamicPfp
            alt="address-avatar"
            nftAvatarMetadata={avatar}
            src={walletGroupAvatar}
            address={primaryAddressForWalletGroup}
            size="xxxl"
          />
          <VStack testID={`${testID}--displayNameContainer`} alignItems="center" gap={0.5}>
            <HStack alignItems="center" gap={1}>
              {walletGroup.isHidden && (
                <Icon
                  testID="wallet-hidden-icon"
                  name="visibleInactive"
                  size="s"
                  color="foregroundMuted"
                />
              )}
              <HeaderDisplay
                displayName={displayName}
                isHidden={walletGroup.isHidden}
                isEditable={!walletGroup.primaryDomainName}
                handleGoToNickname={handleGoToNickname}
              />
            </HStack>
            <TextLegal testID={`${testID}--hidden-text`} as="p">
              {walletGroup.isHidden ? formatMessage(messages.headingHidden) : EMPTY_SPACE}
            </TextLegal>
          </VStack>
        </VStack>
      </VStack>
      {showManageProfileLink && (
        <Option
          testID={`${testID}--profile`}
          onPress={handleGoToProfile}
          label={formatMessage(messages.manageProfile)}
          accessory="arrow"
          outerSpacing={listCellSpacing}
          compact
        />
      )}
      {canClaimSubdomainFromSettings && (
        <Option
          testID={`${testID}--claim`}
          onPress={handleClaimDomain}
          label={formatMessage(messages.claimDomain)}
          accessory="arrow"
          outerSpacing={listCellSpacing}
          compact
        />
      )}
      <Option
        testID={`${testID}--dapps`}
        onPress={handleGoToThemeColor}
        label={formatMessage(messages.themeColor)}
        accessory="arrow"
        outerSpacing={listCellSpacing}
        compact
        detail={
          <HStack justifyContent="flex-end">
            <Box
              borderRadius="roundedFull"
              dangerouslySetBackground={preferenceBackground}
              width={20}
              height={20}
            />
          </HStack>
        }
      />
      <Option
        testID={`${testID}--dapps`}
        onPress={handleGoToConnections}
        label={formatMessage(messages.connectedDapps)}
        accessory="arrow"
        outerSpacing={listCellSpacing}
        compact
      />
      {showPrivateKey && (
        <Option
          testID={`${testID}--private-key-export`}
          onPress={handleGoToPrivateKeyExport}
          label={formatMessage(messages.showPrivateKey)}
          accessory="arrow"
          outerSpacing={listCellSpacing}
          compact
        />
      )}
      <ListCell
        testID={`${testID}--hide`}
        compact
        outerSpacing={listCellSpacing}
        title={
          <HStack alignItems="center" gap={1}>
            <TextBody as="p">{sharedMessages.hideWalletSettingTitle}</TextBody>
            <Tooltip
              testID={`${testID}-tooltip`}
              content={sharedMessages.hideWalletTooltipDetailText}
              placement="bottom"
            >
              <Icon testID={`${testID}-tooltip-icon`} name="info" size="xs" color="foreground" />
            </Tooltip>
          </HStack>
        }
        action={
          <Box onClick={isHideWalletDisabled ? handleDisabledClick : undefined}>
            <Switch
              testID={`${testID}--hideSwitch${walletGroup.isHidden ? '-checked' : ''}`}
              onChange={handleHiddenSwitch}
              checked={walletGroup.isHidden}
              disabled={isHideWalletDisabled}
            />
          </Box>
        }
      />
    </VStack>
  );
});

import { useCallback } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { useImportCustomNetworksViewed } from 'cb-wallet-analytics/settings';
import { useImportCustomNetworks } from 'cb-wallet-data/stores/CustomNetworks/hooks/useImportCustomNetworks';
import { Form, Formik, FormikHelpers } from 'formik';
import { Button, ButtonGroup } from '@cbhq/cds-web/buttons';
import { HeroSquare } from '@cbhq/cds-web/illustrations';
import { VStack } from '@cbhq/cds-web/layout';
import { TextLabel2 } from '@cbhq/cds-web/typography';

import { TextInput } from './ConnectedTextInput';

const messages = defineMessages({
  importCustomNetworksTitle: {
    defaultMessage: 'Import Custom Network',
    description: 'Title for importing custom networks',
  },
  networksJSON: {
    defaultMessage: 'Networks JSON',
    description: 'Label for input where the custom networks JSON should be placed',
  },
  import: {
    defaultMessage: 'Import',
    description: 'Import the list of custom networks',
  },
  importInstructions: {
    defaultMessage: 'Get the JSON by clicking Export on the Networks page',
    description: 'Instructions on how to get the custom networks JSON',
  },
  buttonGroup: {
    defaultMessage: 'Import page actions',
    description: 'Import page actions',
  },
});

const initialValues = { networksJSON: '' };

/* Import Custom Networks Modal */
export function ImportCustomNetworks() {
  const { formatMessage } = useIntl();

  const importCustomNetworks = useImportCustomNetworks();

  const handleImport = async (
    values: typeof initialValues,
    { setStatus, setSubmitting }: FormikHelpers<typeof initialValues>,
  ) => {
    setSubmitting(true);
    try {
      await importCustomNetworks(values.networksJSON);
      setStatus('');
      window.close();
      return;
    } catch (err) {
      const error = err as Error;
      setStatus(error.message);
    } finally {
      setSubmitting(false);
    }
  };

  const handleSubmit: (
    values: typeof initialValues,
    { setStatus, setSubmitting }: FormikHelpers<typeof initialValues>,
  ) => Promise<void> = useCallback(handleImport, [importCustomNetworks]);

  useImportCustomNetworksViewed();

  return (
    <VStack spacing={1}>
      <VStack justifyContent="center" alignItems="center" spacingBottom={5}>
        <HeroSquare name="exploreDecentralizedApps" scaleMultiplier={0.9} />
      </VStack>
      <Formik initialValues={initialValues} onSubmit={handleSubmit}>
        {({ status, isSubmitting }) => (
          <Form>
            <TextInput
              testID="custom-network-name-input"
              label={formatMessage(messages.networksJSON)}
              name="networksJSON"
            />
            <TextLabel2 testID="text-input-error-label" as="span">
              {formatMessage(messages.importInstructions)}
            </TextLabel2>

            <VStack spacing={2}>
              {!!status && (
                <TextLabel2
                  testID="text-input-error-label"
                  as="span"
                  color="negative"
                  spacingBottom={2}
                >
                  {status.split(';').map((msg: string, index: number) => (
                    // eslint-disable-next-line react/no-array-index-key
                    <span key={`error-${index}`}>
                      {msg}
                      <br />
                    </span>
                  ))}
                </TextLabel2>
              )}

              <ButtonGroup block accessibilityLabel={formatMessage(messages.buttonGroup)}>
                <Button
                  testID="custom-network-import-submit"
                  type="submit"
                  variant="primary"
                  loading={isSubmitting}
                >
                  {formatMessage(messages.import)}
                </Button>
              </ButtonGroup>
            </VStack>
          </Form>
        )}
      </Formik>
    </VStack>
  );
}

import { useCallback, useState } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { customNetworksAtom } from 'cb-wallet-data/stores/CustomNetworks/state';
import noop from 'lodash/noop';
import { useRecoilValue } from 'recoil';
import { useToast } from 'wallet-cds-extension/overrides/@cbhq/cds-web/overlays/useToast';
import { useToggler } from '@cbhq/cds-web';
import { Button } from '@cbhq/cds-web/buttons';
import { Collapsible } from '@cbhq/cds-web/collapsible';
import { NativeTextArea, TextInput } from '@cbhq/cds-web/controls';
import { useA11yControlledVisibility } from '@cbhq/cds-web/hooks/useA11yControlledVisibility';
import { VStack } from '@cbhq/cds-web/layout';
import { TextLegal } from '@cbhq/cds-web/typography';

import {
  triggerExportButtonToggleHide,
  triggerExportButtonToggleShow,
} from ':extension/screens/Settings/NetworkListSection/eventing';

const messages = defineMessages({
  exportCustomNetworksShow: {
    description: 'Active button text',
    defaultMessage: 'Copy export data',
  },
  exportCustomNetworksHide: {
    description: 'Inactive button text',
    defaultMessage: 'Hide export data',
  },
  exportCustomNetworksDescription: {
    description: 'Action button description',
    defaultMessage: 'Saves your list of custom networks as JSON string to your clipboard:',
  },
});

/**
 * Export Custom Network section
 */
export function NetworkDataExport() {
  const { formatMessage } = useIntl();
  const toast = useToast();
  const storedCustomNetworks = useRecoilValue(customNetworksAtom);
  const [clipboard, setClipboard] = useState('');
  const [collapsed, { toggle }] = useToggler(true);
  const { triggerAccessibilityProps, controlledElementAccessibilityProps } =
    useA11yControlledVisibility(!collapsed, { accessibilityLabel: 'cds-collapsible' });

  const handleExportCustomNetworks = useCallback(() => {
    toggle();
    if (!collapsed) {
      triggerExportButtonToggleHide();
      return;
    }

    triggerExportButtonToggleShow();
    const copyNetworkJSON = JSON.stringify(storedCustomNetworks);
    navigator.clipboard.writeText(copyNetworkJSON);
    setClipboard(copyNetworkJSON);
    toast.show('Copied to clipboard!', {
      duration: 500,
      bottomOffset: 300,
      onWillHide: () => {
        setTimeout(() => {
          document
            .querySelector("[data-testId='export-textarea']")
            ?.scrollIntoView({ behavior: 'smooth' });
        }, 500);
      },
    });
  }, [collapsed, storedCustomNetworks, toast, toggle]);

  return (
    <VStack spacingTop={3} spacingHorizontal={2} alignItems="center">
      <VStack width={250} spacingBottom={2}>
        <TextLegal as="div" align="center" color="foregroundMuted">
          {formatMessage(messages.exportCustomNetworksDescription)}
        </TextLegal>
      </VStack>

      <Button
        block
        endIcon="copy"
        testID="export-custom-networks-button"
        variant="secondary"
        onPress={handleExportCustomNetworks}
        {...triggerAccessibilityProps}
      >
        {collapsed
          ? formatMessage(messages.exportCustomNetworksShow)
          : formatMessage(messages.exportCustomNetworksHide)}
      </Button>
      <Collapsible
        collapsed={collapsed}
        spacingVertical={2}
        testID="export-custom-networks-collapsible"
        {...controlledElementAccessibilityProps}
      >
        <TextInput
          label=""
          testID="export-textwrapper"
          helperText="Import the above to add custom networks"
          variant="foregroundMuted"
          inputNode={
            <NativeTextArea
              rows={8}
              cols={35}
              onChange={noop}
              value={clipboard}
              compact
              testID="export-textarea"
            />
          }
        />
      </Collapsible>
    </VStack>
  );
}

import { memo, Suspense, useCallback, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import {
  triggerNotificationSettingsToggled,
  useNotificationSettingsViewed,
} from 'cb-wallet-analytics/notifications/settingsEvents';
import { useOverridableKillSwitch } from 'cb-wallet-data/hooks/KillSwitches/useOverridableKillSwitch';
import { getKillSwitchByPlatform } from 'cb-wallet-data/hooks/KillSwitches/utils/getKillSwitchByPlatform';
import {
  PreferencesMap,
  PreferencesMapValueType,
  resolveDynamicDescriptor,
} from 'cb-wallet-data/stores/Notifications/channels/preferences';
import { useNotificationPreferences } from 'cb-wallet-data/stores/Notifications/hooks/useNotificationPreferences';
import {
  matchingKey,
  useUpdateNotificationPreference,
} from 'cb-wallet-data/stores/Notifications/hooks/useUpdateNotificationPreference';
import { SimplifiedNotificationPreference } from 'cb-wallet-data/stores/Notifications/types/NotificationPreference';
import { useToast } from 'wallet-cds-extension/overrides/@cbhq/cds-web/overlays/useToast';
import { DEFAULT_VIEWPORT_FULL_WIDTH } from 'wallet-cds-extension/util/constants/layout';
import { ListCellFallback } from '@cbhq/cds-web/cells';
import { Switch } from '@cbhq/cds-web/controls/Switch';
import { VStack } from '@cbhq/cds-web/layout';
import { TextTitle3 } from '@cbhq/cds-web/typography';

import { Option } from './components/Option';

export const messages = defineMessages({
  errorToast: {
    defaultMessage: 'Something went wrong saving your notification preferences',
    description: 'Message in toast stating there was an error saving notification preferences.',
  },
  turnOnOffAlert: {
    defaultMessage: 'Turn on/off alerts',
    description: 'Header for notifications group',
  },
});

type PreferenceRowProps = {
  preference: SimplifiedNotificationPreference;
  metadata: PreferencesMapValueType;
  onToggle: (preference: SimplifiedNotificationPreference) => void;
  enabled: boolean;
  testID?: string;
};

const PreferenceRow = memo(function PreferenceRow({
  metadata,
  preference,
  onToggle,
  enabled,
  testID,
}: PreferenceRowProps) {
  const { title, description, killSwitch } = metadata;
  const intlShape = useIntl();
  const isFeatureEnabled = !useOverridableKillSwitch(getKillSwitchByPlatform(killSwitch));
  const toggle = useCallback(() => {
    onToggle(preference);
  }, [onToggle, preference]);

  if (!isFeatureEnabled) {
    return null;
  }
  return (
    <Option
      testID="notification-preference-row"
      label={resolveDynamicDescriptor(intlShape, title)}
      description={description && resolveDynamicDescriptor(intlShape, description)}
      multiline
      action={<Switch testID={testID} onChange={toggle} checked={enabled} />}
      labelOverflow="wrap"
      descriptionMaxWidth={DEFAULT_VIEWPORT_FULL_WIDTH}
    />
  );
});

const NotificationSettingsContent = memo(function NotificationSettingsContent() {
  const { formatMessage } = useIntl();
  const toast = useToast();
  const preferences = useNotificationPreferences({ suspense: true });
  const { mutate: updateNotificationPreference } = useUpdateNotificationPreference({
    onError: () => toast.show(formatMessage(messages.errorToast)),
  });

  useNotificationSettingsViewed();

  const togglePreference = useCallback(
    (preference: SimplifiedNotificationPreference) => {
      triggerNotificationSettingsToggled(preference);

      updateNotificationPreference({
        ...preference,

        currentlyEnabled: preference.enabled,
        switchingTo: !preference.enabled,
      });
    },
    [updateNotificationPreference],
  );

  const preferenceRows = useMemo(() => {
    if (!preferences) {
      return null;
    }

    return preferences.map((preference: SimplifiedNotificationPreference, index: number) => {
      const metadata = PreferencesMap[matchingKey(preference)];

      if (!metadata) {
        return null;
      }

      return (
        <PreferenceRow
          key={`${preference.type}${preference.key}`}
          preference={preference}
          metadata={metadata}
          onToggle={togglePreference}
          enabled={preference.enabled}
          testID={`notification-preference-row-switch-${index}`}
        />
      );
    });
  }, [preferences, togglePreference]);

  return (
    <VStack>
      <TextTitle3 as="h3" spacingStart={3} spacingVertical={2}>
        {formatMessage(messages.turnOnOffAlert)}
      </TextTitle3>
      <VStack>{preferenceRows}</VStack>
    </VStack>
  );
});

function Fallback() {
  return (
    <VStack spacingHorizontal={1}>
      <ListCellFallback title description detail subdetail />
      <ListCellFallback title description detail subdetail />
    </VStack>
  );
}

function NotificationSettingsContainer() {
  return (
    <Suspense fallback={<Fallback />}>
      <NotificationSettingsContent />
    </Suspense>
  );
}

export const NotificationSettings = memo(NotificationSettingsContainer);

