const messages = defineMessages({
  title: {
    defaultMessage: 'Debug Private Keys',
    description: 'Page title',
  },
  createPrivateKeysTitle: {
    defaultMessage: 'Create Private Keys',
    description: 'Create Private Keys section title',
  },
  instructions: {
    defaultMessage: 'This derives private keys from a newly generated mnemonic.',
    description: 'Instructions for this section',
  },
  generatedMnemonic: {
    defaultMessage: 'Mnemonic',
    description: 'Label',
  },
  createPrivateKeys: {
    defaultMessage: 'Create Private Keys from Mnemonic',
    description: 'Section CTA',
  },
});

export function DebugPrivateKeys() {
  const { formatMessage } = useIntl();
  const history = useHistory();
  const createAccountAndWallets = useCreateAccountAndWallets({ method: 'import' });
  const [mnemonic, setMnemonic] = useState<string | undefined>(undefined);
  const [password, setPassword] = useState<string>('');
  const [numToCreate, setNumToCreate] = useState<number>(1);
  const [isCreating, setIsCreating] = useState<boolean>(false);

  const renderFallback = useCallback(() => {
    return <ErrorFallback onPrimaryButtonPress={history?.goBack} />;
  }, [history?.goBack]);

  const createPrivateKeys = useCallback(async () => {
    setIsCreating(true);

    const generatedMnemonic = await generateMnemonic();

    /* eslint-disable no-await-in-loop */
    for (let i = 0; i < numToCreate; i++) {
      const { privateKey } = await getEthereumWalletKeyPair(BigInt(i), generatedMnemonic);
      await createAccountAndWallets({
        password,
        secret: privateKey.toString('hex'),
      });
    }
    /* eslint-enable no-await-in-loop */

    setIsCreating(false);
    setMnemonic(generatedMnemonic);
  }, [createAccountAndWallets, numToCreate, password]);

  const handleChangeNumToCreate = useCallback(
    (event: React.ChangeEvent<HTMLInputElement>) => setNumToCreate(Number(event.target.value)),
    [],
  );

  const handleChangePassword = useCallback(
    (event: React.ChangeEvent<HTMLInputElement>) => setPassword(event.target.value),
    [],
  );

  return (
    <ErrorBoundary renderFallback={renderFallback}>
      <VStack height="100%" overflow="scroll">
        <NavTitle title={formatMessage(messages.title)} />
        <VStack>
          <TextTitle3 as="h2">{formatMessage(messages.createPrivateKeysTitle)}</TextTitle3>
          <TextBody as="p">{formatMessage(messages.instructions)}</TextBody>
        </VStack>
        <VStack spacingTop={2}>
          <TextInput
            label="Num of private keys to create"
            type="number"
            value={numToCreate}
            onChange={handleChangeNumToCreate}
          />
        </VStack>
        <VStack spacingTop={2}>
          <TextInput
            label="Password for storage encryption (This MUST match app unlock password. There is no validation. If it is incorrect, the private key will be unlockable."
            type="password"
            value={password}
            onChange={handleChangePassword}
          />
          <VStack spacingTop={2}>
            <Button
              disabled={Boolean(!password) || Boolean(!numToCreate)}
              loading={isCreating}
              onPress={createPrivateKeys}
            >
              {formatMessage(messages.createPrivateKeys)}
            </Button>
          </VStack>
          {mnemonic && (
            <VStack spacingTop={2}>
              <TextInput label="Backing mnemonic" readOnly value={mnemonic} />
            </VStack>
          )}
        </VStack>
      </VStack>
    </ErrorBoundary>
  );
}

