  miamiThemeColorConfigs,
  MiamiThemeColorPreference,
  themeColorConfigs,
  ThemeColorPreference,
} from 'cb-wallet-data/stores/ThemeColors/themeColorConfigs';
import { useSetThemeColor } from 'cb-wallet-data/stores/User/hooks/useSetThemeColor';
import { useThemeColor } from 'cb-wallet-data/stores/User/hooks/useThemeColor';
import { NavBar } from 'wallet-cds-extension/components/Header/NavBar';
