export function AnnouncementCardsDesigner() {
  const routeToLandingPage = useRouteToLandingPage();
  const { formatMessage } = useIntl();
  const { goBack } = useHistory();

  const [title, setTitle] = useState<string>('This is a test title');
  const [description, setDescription] = useState<string>('This is a test description');
  const [deeplinkUrl, setDeeplinkUrl] = useState<string | undefined>();
  const [externalUrl, setExternalUrl] = useState<string | undefined>();
  const [spotSquareImageName, setSpotSquareImageName] = useState<SpotSquareName | undefined>(
    'defiNfts',
  );
  const [imageUrl, setImageUrl] = useState<string | undefined>();

  const announcementCardFields: AnnouncementCardFields[] = useMemo(() => {
    return [
      {
        name: 'test',
        title,
        description,
        spotSquareImageName,
        imageUrl,
        deeplinkUrl,
        externalUrl,
        priority: 0,
      },
    ];
  }, [deeplinkUrl, description, externalUrl, imageUrl, spotSquareImageName, title]);

  const handlePress = useCallback(
    function getHandlePressCallback(fields: AnnouncementCardFields) {
      return () => {
        if (fields?.deeplinkUrl) {
          routeToLandingPage(fields?.deeplinkUrl);
        } else if (fields?.externalUrl) {
          chrome.tabs.create({ url: fields?.externalUrl });
        }
      };
    },
    [routeToLandingPage],
  );

  const announcements = useMemo(
    () =>
      announcementCardFields.map((fields) => {
        let image = null;
        if (fields?.spotSquareImageName) {
          image = (
            <SpotSquare
              name={fields.spotSquareImageName}
              dimension="96x96"
              scaleMultiplier={0.66}
            />
          );
        } else {
          image = (
            <Box spacing={0.5}>
              <RemoteImage source={fields?.imageUrl} width={58} height={58} shape="square" />
            </Box>
          );
        }

        return {
          key: fields?.name,
          title: fields?.title,
          media: image,
          description: fields?.description,
          onPress: handlePress(fields),
          onDismiss: noop,
          priority: fields?.priority ?? 4,
          deeplinkUrl,
          externalUrl,
        } as Announcement;
      }),
    [announcementCardFields, deeplinkUrl, externalUrl, handlePress],
  );

  const handleTitleChange = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    setTitle(event.target.value);
  }, []);
  const handleDescriptionChange = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    setDescription(event.target.value);
  }, []);

  const handleDeeplinkChange = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    setDeeplinkUrl(event.target.value);
  }, []);

  const handleExternalUrlChange = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    setExternalUrl(event.target.value);
  }, []);

  const handleSpotSquareImageNameChange = useCallback(
    (event: React.ChangeEvent<HTMLInputElement>) => {
      setSpotSquareImageName(event.target.value as SpotSquareName);
    },
    [],
  );

  const handleImageUrlChange = useCallback((event: React.ChangeEvent<HTMLInputElement>) => {
    setImageUrl(event.target.value);
  }, []);

  return (
    <Screen
      header={
        <NavBar variant="secondary" title={formatMessage(messages.title)} handleBack={goBack} />
      }
    >
      <VStack justifyContent="space-between" gap={2} width="100%" spacingHorizontal={3}>
        <AnnouncementCard announcement={announcements[0]} onDismiss={noop} />

        <TextBody as="p">{formatMessage(messages.pageDescription)}</TextBody>
        <VStack justifyContent="space-between" gap={1}>
          <TextInput
            name="title"
            variant="foregroundMuted"
            label={formatMessage(messages.titleEntryLabel)}
            placeholder={formatMessage(messages.titleEntryPlaceholder)}
            onChange={handleTitleChange}
          />
          <TextInput
            name="description"
            variant="foregroundMuted"
            label={formatMessage(messages.descriptionEntryLabel)}
            placeholder={formatMessage(messages.descriptionEntryPlaceholder)}
            onChange={handleDescriptionChange}
          />

          <TextBody as="p">{formatMessage(messages.urlDescription)}</TextBody>

          <TextInput
            name="deeplink"
            variant="foregroundMuted"
            label={formatMessage(messages.deeplinkEntryLabel)}
            placeholder={formatMessage(messages.deeplinkEntryPlaceholder)}
            onChange={handleDeeplinkChange}
          />
          <TextInput
            name="externalUrl"
            variant="foregroundMuted"
            label={formatMessage(messages.externalUrlEntryLabel)}
            placeholder={formatMessage(messages.externalUrlEntryLabel)}
            onChange={handleExternalUrlChange}
          />

          <TextBody as="p">{formatMessage(messages.imageDescription)}</TextBody>
          <TextInput
            name="spotSquareImageName"
            variant="foregroundMuted"
            label={formatMessage(messages.spotSquareImageEntryLabel)}
            placeholder={formatMessage(messages.spotSquareImageEntryPlaceholder)}
            onChange={handleSpotSquareImageNameChange}
          />

          <TextInput
            name="imageUrl"
            variant="foregroundMuted"
            label={formatMessage(messages.imageUrlEntryLabel)}
            placeholder={formatMessage(messages.imageUrlEntryPlaceholder)}
            onChange={handleImageUrlChange}
          />
        </VStack>
      </VStack>
    </Screen>
  );
}

