/**
 * This should only be used in the context of the settings screen
 * NEVER use this in the context of the escape hatch or banned location gate.
 */
export function ShowPrivateKey() {
  const { formatMessage } = useIntl();
  const history = useHistory();
  const activeAccountId = useActiveAccountId();
  const activeWalletGroup = useActiveWalletGroup();
  const { accountId = activeAccountId, walletIndex = activeWalletGroup?.walletIndex.toString() } =
    useParams<{
      accountId?: string;
      walletIndex?: string;
    }>();

  const [isChecked, setIsChecked] = useState<boolean>(false);
  const [passwordError, setPasswordError] = useState<boolean>(false);
  const [password, setPassword] = useState<string>('');

  useShowPrivateKeyViewed();

  const handleGoBack = useCallback(() => history.goBack(), [history]);

  const onPasswordChange = useCallback(
    (value: string) => {
      if (passwordError) {
        setPasswordError(!passwordError);
      }
      setPassword(value);
    },
    [passwordError],
  );

  const handleOnNext = useCallback(async () => {
    logEvent('show_private_key.next_btn', {
      loggingId: '5a938d85-1977-4438-b460-e15e23b2f822',
      action: ActionType.click,
      componentType: ComponentType.button,
    });

    const submitPasswordResult = await appLockRepository.submitPassword(
      password,
      decodeURIComponent(accountId),
      SecretAccessContext.ShowRecoveryPhrase,
    );

    if (submitPasswordResult.status === 'FAILURE') {
      logEvent('show_private_key.password_error', {
        loggingId: '9e4c70ac-1afa-4dee-8efe-a591b18506e4',
        action: ActionType.render,
        componentType: ComponentType.text,
      });
      setPasswordError(true);

      return;
    }

    setPasswordError(false);
    logEvent('show_private_key.password_success', {
      loggingId: '98f1442e-16cd-4e94-8a0d-167403881318',
      action: ActionType.render,
      componentType: ComponentType.unknown,
    });

    if (!walletIndex) {
      handleGoBack();
      return;
    }
    const url = generatePath(RoutesEnum.YOUR_PRIVATE_KEY, {
      accountId,
      walletIndex,
    });
    history.replace(url);
  }, [accountId, history, handleGoBack, password, walletIndex]);

  const disabled = !isChecked || password.length <= 0;

  const handleCheckToggle = useCallback(() => {
    setIsChecked((checked) => !checked);
  }, []);

  const handleBackPress = useCallback(() => history.goBack(), [history]);

  return (
    <Screen
      height="100%"
      testID="show-private-key-container"
      header={<NavBar handleBack={handleBackPress} />}
    >
      <VStack spacingHorizontal={3} gap={2} spacingBottom={4}>
        <TextTitle1 as="h3">{formatMessage(messages.pageTitle)}</TextTitle1>
        <TextBody as="div" color="foregroundMuted">
          {formatMessage(messages.pageInstructions)}
        </TextBody>
      </VStack>
      <VStack spacingHorizontal={3} gap={1} flexGrow={1}>
        <ValidatedTextInput
          testID="show-private-key-password"
          type="password"
          name="password"
          label={formatMessage(messages.password)}
          value={password}
          autoFocus
          onChange={onPasswordChange}
          givenError={passwordError ? formatMessage(messages.incorrectPassword) : undefined}
          onEnter={disabled ? undefined : handleOnNext}
        />
        <Checkbox
          testID="show-private-key-checkbox"
          label={<TextLegal as="span">{formatMessage(messages.pageTermsAndConditions)}</TextLegal>}
          isChecked={isChecked}
          onCheckToggle={handleCheckToggle}
        />
      </VStack>
      <Box spacingHorizontal={3} spacingBottom={3}>
        <Button testID="show-private-key-next-btn" block onPress={handleOnNext} disabled={disabled}>
          {formatMessage(messages.next)}
        </Button>
      </Box>
    </Screen>
  );
}

