export const TOSUpdate = memo(function TOSUpdate() {
  const { goBack, push } = useHistory();
  const { formatMessage } = useIntl();
  const { openModal, closeModal } = useModal();
  const { isMnemonicAccount } = useActiveAccount();

  useTOSUpdateViewed();

  const setViewedTOSUpdate = useSetRecoilState(viewedTOSUpdateAtom);

  const handleAccept = useCallback(() => {
    logTOSUpdateAcceptClicked();
    setViewedTOSUpdate(true);
    goBack();
  }, [goBack, setViewedTOSUpdate]);

  const handleDisagree = useCallback(() => {
    logTOSUpdateSignoutTrayClicked();
    closeModal();
    // Hardware Wallet or WalletLink don't have mnemonic locally,
    // so we skip backup step
    if (isMnemonicAccount) {
      push('/tosMoveFunds');
    } else {
      push('/tosSignoutConfirmation');
    }
  }, [isMnemonicAccount, closeModal, push]);

  const handleCloseConfirmation = useCallback(() => {
    logTOSUpdateCloseTrayClicked();
    closeModal();
  }, [closeModal]);

  const handleClose = useCallback(() => {
    logTOSUpdateCloseClicked();
    openModal(
      <TOSUpdateModal
        visible
        onRequestClose={handleCloseConfirmation}
        handleDisagree={handleDisagree}
      />,
    );
  }, [handleCloseConfirmation, handleDisagree, openModal]);

  return (
    <Screen
      header={
        <NavBar
          variant="secondary"
          title={formatMessage(messages.navBarTitle)}
          actions={
            <Pressable
              as="button"
              onPress={handleClose}
              testID="nav-close-button"
              background="transparent"
            >
              <Icon name="close" size="s" color="foreground" />
            </Pressable>
          }
        />
      }
      footer={
        <Box spacingHorizontal={3} spacingTop={2} background="background" width="100%">
          <Button variant="primary" onPress={handleAccept} testID="accept-terms-button" block>
            {formatMessage(messages.agreeBtn)}
          </Button>
        </Box>
      }
    >
      <Box spacingBottom={4} spacingHorizontal={3}>
        <TermsUpdate />
      </Box>
    </Screen>
  );
});

