import { useSwapAnalyticsDetails } from ':extension/screens/Trade/useSwapAnalyticsDetails';
import { form, stepper } from ':extension/screens/TransactionHistory/SpeedUpAndCancel/flow';

type SpeedUpCancelStepProps = {
  wallet: Wallet;
  originalTransaction: Transaction;
  isSpeedUp: boolean;
};

/**
 * @property wallet associated wallet for the transaction
 * @property originalTransaction the original transaction that is currently pending that user wishes to speed up
 * @property isSpeedUp true if this is a request to speed up the transaction
 */
export function SpeedUpCancelStep({
  wallet,
  originalTransaction,
  isSpeedUp,
}: SpeedUpCancelStepProps) {
  const { goToStep } = useStepper(stepper);
  const { goBack } = useHistory();
  const { unsignedTxResult, txSigningError, customGas } = useFields(form);
  const analyticsFeeData = useAnalyticsFeeData(unsignedTxResult.value?.transaction, wallet);
  const chainDetails = useSwapAnalyticsDetails();

  useSpeedUpCancelScreenViewed(isSpeedUp ? 'speedup' : 'cancel', wallet.blockchain.rawValue);

  const activeWalletGroupId = useActiveWalletGroupId();
  const feeWallet = useTxFeeWallet(activeWalletGroupId, originalTransaction);

  if (!feeWallet) {
    throw new Error('No fee wallet in SpeedUpCancelStep');
  }

  const networkFeeInfo = useSpeedUpAndCancelFees(originalTransaction, wallet);

  const { title, header, body, networkFeeLabel, tooltip, buttonLabel, backLabel, feeFiatRange } =
    useFormattedSpeedUpAndCancelTransaction({
      txSubmissionType: isSpeedUp ? 'speedUp' : 'cancel',
      originalTransaction,
      wallet,
      networkFeeInfo,
      unsignedTxResult: unsignedTxResult.value,
    });

  const handleError = useCallback(
    (error: Error) => {
      txSigningError.onChange(error);
      goToStep('status');
    },
    [txSigningError, goToStep],
  );

  const handleSuccess = useCallback(async () => {
    goToStep('status');
  }, [goToStep]);

  const handleUnlock = useHandleUnlockForSigning();

  const { signAndSubmitStandalone, isSignAndSubmitStandaloneLoading } =
    useSpeedUpAndCancelTransaction({
      txSubmissionType: isSpeedUp ? 'speedUp' : 'cancel',
      originalTransaction,
      wallet,
      handleUnlock: handleUnlock(wallet.accountId),
      handleSuccess,
      handleError,
      unsignedTxResult: unsignedTxResult.value,
    });

  useOnMount(() => {
    if (!unsignedTxResult.value) {
      const result = generateUnsignedSpeedUpCancelTx({
        txSubmissionType: isSpeedUp ? 'speedUp' : 'cancel',
        originalTransaction,
        wallet,
        networkFeeInfo,
      });
      result.then((unsignedTransaction) => {
        unsignedTxResult.onChange(unsignedTransaction);
      });
    }
  });

  const analyticsId = originalTransaction.metadata.get(TxMetadataKey_analyticsId)?.toString();
  const {
    gasLimit,
    chainId,
    feeCurrencyCode,
    minFeeInUSD,
    maxFeeInUSD,
    minFeeInCrypto,
    maxFeeInCrypto,
  } = analyticsFeeData as FeeAnalytics1559;

  useEffect(
    function sendFeeAnalytics() {
      if (unsignedTxResult.value?.transaction && !customGas.value) {
        triggerSpeedUpCancelUnsignedTxGas(isSpeedUp ? 'speedup' : 'cancel', {
          gasLimit,
          analyticsId,
          chainId,
          feeCurrencyCode,
          minFeeInUSD,
          maxFeeInUSD,
          maxFeeInCrypto,
          minFeeInCrypto,
          blockchain: wallet.blockchain.rawValue,
        });
      }
    },
    [
      unsignedTxResult.value?.transaction,
      minFeeInUSD,
      maxFeeInUSD,
      maxFeeInCrypto,
      minFeeInCrypto,
      gasLimit,
      analyticsId,
      chainId,
      feeCurrencyCode,
      customGas.value,
      isSpeedUp,
      wallet.blockchain.rawValue,
    ],
  );

  const is1559Enabled = useMemo(() => {
    return isNetwork1559Enabled(wallet.network);
  }, [wallet.network]);

  const handleCustomGas = useCallback(() => {
    goToStep('adjustGasCustom');
  }, [goToStep]);

  const handleOnSend = useCallback(() => {
    triggerSpeedUpCancelButtonClicked(isSpeedUp ? 'speedup' : 'cancel', wallet.blockchain.rawValue);
    return signAndSubmitStandalone();
  }, [isSpeedUp, signAndSubmitStandalone, wallet.blockchain.rawValue]);

  const transactionDetailsErrors = useTransactionDetailsErrors({
    wallet,
    unsignedTx: unsignedTxResult.value?.transaction,
    feeWallet,
    flow: 'speedUpCancel',
  });
  const isAdjustableMinerFeeEnabled = useIsAdjustableMinerFeeEnabled() && is1559Enabled;

  return (
    <VStack height="552px">
      <NavTitle onBack={goBack} title={title} />
      <VStack spacingHorizontal={3}>
        <VStack spacing={3} bordered borderRadius="rounded" elevation={1}>
          {isSpeedUp ? (
            <Icon testID="speedUpHeaderIcon" name="lightningBolt" size="l" />
          ) : (
            <Icon testID="cancelHeaderIcon" name="close" size="l" color="negative" bordered />
          )}
          <TextLabel2 as="p" spacingTop={1}>
            {header}
          </TextLabel2>
          <TextTitle3 testID="txn_to_address" as="h4">
            {originalTransaction.entityDisplayName(true)}
          </TextTitle3>
        </VStack>

        <HStack justifyContent="space-between" spacingTop={3}>
          <HStack>
            <TextBody as="p">{networkFeeLabel}</TextBody>
            <div className={questionMarkIcon}>
              <Tooltip content={tooltip} placement="bottom">
                <Icon name="info" size="xs" color="foregroundMuted" />
              </Tooltip>
            </div>
          </HStack>

          <HStack>
            <TextBody testID="txn_fee_range" as="p" color="foregroundMuted">
              {feeFiatRange ?? <Fallback width={100} height={20} />}
            </TextBody>
            {isAdjustableMinerFeeEnabled && (
              <Pressable
                testID="adjustable_gas_entry"
                as="button"
                onPress={handleCustomGas}
                background="transparent"
              >
                <Icon name="gear" size="s" color="foreground" spacingStart={1} />
              </Pressable>
            )}
          </HStack>
        </HStack>

        <TextBody testID="speedup_cancel_description" color="foregroundMuted" spacingTop={2} as="p">
          {body}
        </TextBody>

        <VStack position="absolute" width="100%" bottom={0} right={0}>
          {transactionDetailsErrors ? (
            <TxDetailError
              chainDetails={chainDetails}
              message={transactionDetailsErrors.message}
              isDismissible={transactionDetailsErrors.isDismissible}
              showErrorIcon={transactionDetailsErrors.showErrorIcon}
              analytics={transactionDetailsErrors.analytics}
            />
          ) : undefined}
          <HStack alignItems="flex-end" height="100%" spacingHorizontal={3} gap={2} spacingTop={1}>
            <Button testID="back_button" block onPress={goBack} variant="secondary">
              {backLabel}
            </Button>
            <Button
              onPress={handleOnSend}
              block
              variant={isSpeedUp ? 'primary' : 'negative'}
              disabled={isSignAndSubmitStandaloneLoading || transactionDetailsErrors?.isDisabled}
              loading={isSignAndSubmitStandaloneLoading}
              testID="speedup_cancel_button"
            >
              {buttonLabel}
            </Button>
          </HStack>
        </VStack>
      </VStack>
    </VStack>
  );
}

const questionMarkIcon = css`
  cursor: pointer;
  margin-top: auto;
  margin-bottom: auto;
  margin-left: 8px;
  span:hover {
    /* !important here because CDS sets color attribute in-line */
    color: var(--primary) !important;
  }
`;

