import { useAssetWatchlistState } from 'cb-wallet-data/stores/Watchlist/hooks/useAssetWatchlistState';
import { useRemoveFromWatchlist } from 'cb-wallet-data/stores/Watchlist/hooks/useRemoveFromWatchlist';
