type Props = {
  address: string;
  index: number;
  item: ExploreAssetResponse;
};

export const WatchlistDiscoveryCell = memo(function WatchlistDiscoveryCell({
  address,
  index,
  item,
}: Props) {
  const history = useHistory();

  const { isWatchable, isWatching, optimisticUpdate, resetUpdate } = useAssetWatchlistState({
    networkId: item.networkId,
    chainId: item.chainId,
    contractAddress: item.address,
    symbol: item.currencyCode,
    uuid: item.uuid,
    walletAddress: address,
  });

  const watchedAsset = useWatchlistItem({
    address: item.address,
    networkId: item.networkId,
    blockchain: item.blockchain,
    chainId: item.chainId,
    decimals: item.decimals,
    name: item.name,
    symbol: item.currencyCode,
    uuid: item.uuid,
  });

  const eventData = useMemo(
    () => ({
      chainName: item.blockchain,
      entityName: item.name,
      entityType: EntityTypeEnum.ASSET,
      rankIndex: index,
    }),
    [index, item.blockchain, item.name],
  );

  const cellClickEvent = useClickWatchlistDiscoveryCardEvent(eventData);
  const viewEvent = useViewWatchlistDiscoveryCardEvent(eventData);

  useOnMount(viewEvent);

  const watchEvent = useWatchlistButtonEvent({
    entityName: item.name,
    chainName: item.blockchain,
  });

  const activeWalletGroupId = useActiveWalletGroupId();
  const getExploreAssetWallet = useGetExploreAssetWallet(activeWalletGroupId);
  const assetWallet = getExploreAssetWallet(watchedAsset.id);

  const { formattedPercent, percentColor, percentArrow } = useGetPriceDetail(
    item.currencyCode,
    item.uuid,
    true, // no need to fetch / cache price history
  );

  const handleNavigation = useCallback(() => {
    cellClickEvent();
    history.push(
      `/portfolio/crypto/${encodeURIComponent(assetWallet?.id ?? watchedAsset.id)}/${
        AssetDetailSource.Explore
      }`,
    );
  }, [assetWallet?.id, cellClickEvent, history, watchedAsset.id]);

  const formattedAmount = useWatchedAssetPrice(watchedAsset);

  const assetLike = useMemo<AssetLikeProps>(
    () => ({
      currencyCode: watchedAsset.symbol,
      iconUrl: watchedAsset.imageUrl,
      showIconTooltipOverride: false,
    }),
    [watchedAsset.imageUrl, watchedAsset.symbol],
  );

  const handleError = useCallback(
    (error: ErrorOrAny) => {
      resetUpdate();
      cbReportError({
        context: 'component_error',
        error: new Error(`WatchlistDiscoveryCell: ${error}`),
        severity: 'error',
        isHandled: false,
        isUserVisible: true,
      });
    },
    [resetUpdate],
  );

  const handleSuccess = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ({ isWatchingUpdate }: any) => {
      watchEvent({ componentName: isWatchingUpdate ? 'add' : 'remove' });
    },
    [watchEvent],
  );

  const { addToWatchlist, isAdding } = useAddToWatchlist({
    blockchain: item.blockchain,
    networkId: item.networkId,
    chainId: item.chainId,
    contractAddress: item.address,
    handleError,
    handleSuccess,
    symbol: item.currencyCode,
    type: 'OBJECT_TYPE_ASSET',
    uuid: item.uuid,
    walletAddress: address,
  });

  const { removeFromWatchlist, isRemoving } = useRemoveFromWatchlist({
    networkId: item.networkId,
    chainId: item.chainId,
    contractAddress: item.address,
    handleError,
    handleSuccess,
    symbol: item.currencyCode,
    type: 'OBJECT_TYPE_ASSET',
    walletAddress: address,
  });

  const handleWatchlistUpdate = useCallback(
    (e: ErrorOrAny) => {
      e.stopPropagation();
      optimisticUpdate();
      if (isWatching) {
        removeFromWatchlist();
        return;
      }
      addToWatchlist();
    },
    [addToWatchlist, isWatching, optimisticUpdate, removeFromWatchlist],
  );

  const unwatchableAssetEvent = useUnwatchableAssetEvent({
    chainName: item.blockchain,
    contractAddress: item.address ?? '',
    entityName: item.name,
    componentName: 'watchlist_discovery',
  });

  useEffect(
    function reportUnwatchableAsset() {
      if (!isWatchable) {
        unwatchableAssetEvent();
      }
    },
    [unwatchableAssetEvent, isWatchable],
  );

  if (!isWatchable) {
    return null;
  }

  return (
    <Pressable
      borderRadius="roundedLarge"
      background="backgroundAlternate"
      onPress={handleNavigation}
    >
      <ListCell
        media={<AssetIcon asset={assetLike} width={32} height={32} />}
        title={
          <TextHeadline as="h1" noWrap overflow="truncate">
            {item.name}
          </TextHeadline>
        }
        description={
          <TextLabel2 as="p" color="foregroundMuted">
            {item.currencyCode}
          </TextLabel2>
        }
        detail={
          <HStack justifyContent="flex-end" gap={1}>
            <VStack>
              <TextLabel2 as="p" align="end">
                {formattedAmount}
              </TextLabel2>
              <TextBody as="p" color={percentColor} align="end">
                {`${percentArrow} ${formattedPercent}`}
              </TextBody>
            </VStack>
            <IconButton
              name={isWatching ? 'starActive' : 'starInactive'}
              onPress={handleWatchlistUpdate}
              disabled={isAdding || isRemoving}
              variant={isWatching ? 'primary' : 'secondary'}
              testID="watchlist-discovery-toggle"
              transparent
              compact
            />
          </HStack>
        }
        testID="watchlist-discovery-cell"
        compact
      />
    </Pressable>
  );
});

